INDEX_HTML = '<!DOCTYPE html>\n<html lang="ko">\n  <head>\n    <meta charset="utf-8" />\n    <meta name="viewport" content="width=device-width, initial-scale=1, viewport-fit=cover" />\n    <meta name="color-scheme" content="light dark" />\n    <meta name="theme-color" content="#1a1a1a" />\n    <title>우아한빅토리 스튜디오</title>\n    <link rel="preconnect" href="https://fonts.googleapis.com" />\n    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin />\n    <link\n      href="https://fonts.googleapis.com/css2?family=IBM+Plex+Sans:wght@400;600;700&family=Plus+Jakarta+Sans:wght@700;800&display=swap"\n      rel="stylesheet"\n    />\n    <style>\n/* Reddit-style: high-contrast header, orange accent, dotted canvas, lifted cards */\n:root {\n  --canvas: #c9ccd1;\n  --canvas-dot: rgba(0, 0, 0, 0.07);\n  --card: #ffffff;\n  --border: #e1e4e8;\n  --border-strong: #b7bcc4;\n  --text: #0f0f0f;\n  --meta: #5c5f62;\n  --link: #006cbf;\n  --orange: #ff4500;\n  --orange-hot: #ff6a33;\n  --orange-hover: #e03d00;\n  --header-dark: #1a1a1b;\n  --header-border: #343536;\n  --shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.06);\n  --shadow-card: 0 4px 14px rgba(0, 0, 0, 0.12), 0 0 0 1px rgba(0, 0, 0, 0.04);\n  --shadow-card-hover: 0 8px 24px rgba(0, 0, 0, 0.14), 0 0 0 1px rgba(255, 69, 0, 0.12);\n  --radius: 6px;\n  --radius-card: 10px;\n  --tap-min: 46px;\n  --font: "IBM Plex Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial,\n    "Apple SD Gothic Neo", "Noto Sans KR", sans-serif;\n  --font-brand: "Plus Jakarta Sans", var(--font);\n}\n\n@media (prefers-color-scheme: dark) {\n  :root {\n    --canvas: #030303;\n    --canvas-dot: rgba(255, 255, 255, 0.04);\n    --card: #1a1a1b;\n    --border: #343536;\n    --border-strong: #56585a;\n    --text: #d7dadc;\n    --meta: #9fa1a3;\n    --link: #58a6ff;\n    --orange: #ff4500;\n    --orange-hot: #ff7849;\n    --orange-hover: #ff6a33;\n    --header-dark: #0b0b0c;\n    --header-border: #1f1f1f;\n    --shadow-sm: 0 1px 3px rgba(0, 0, 0, 0.5);\n    --shadow-card: 0 4px 18px rgba(0, 0, 0, 0.55), 0 0 0 1px #2a2a2b;\n    --shadow-card-hover: 0 10px 28px rgba(0, 0, 0, 0.65), 0 0 0 1px rgba(255, 69, 0, 0.35);\n  }\n}\n\n* {\n  box-sizing: border-box;\n}\n\nhtml {\n  -webkit-text-size-adjust: 100%;\n}\n\nbody {\n  margin: 0;\n  min-height: 100dvh;\n  font-family: var(--font);\n  font-size: 15px;\n  background-color: var(--canvas);\n  background-image: radial-gradient(circle at 1px 1px, var(--canvas-dot) 1px, transparent 0);\n  background-size: 18px 18px;\n  color: var(--text);\n  line-height: 1.55;\n  padding-bottom: env(safe-area-inset-bottom, 0);\n}\n\na {\n  color: var(--link);\n  text-decoration: none;\n}\na:hover {\n  text-decoration: underline;\n}\n\n/* —— Top bar (dark, Reddit-app feel) —— */\n.site-header {\n  position: sticky;\n  top: 0;\n  z-index: 200;\n  background: linear-gradient(180deg, #252526 0%, var(--header-dark) 100%);\n  border-bottom: 3px solid var(--orange);\n  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.25);\n  padding-top: env(safe-area-inset-top, 0);\n}\n\n@media (prefers-color-scheme: dark) {\n  .site-header {\n    background: linear-gradient(180deg, #121213 0%, var(--header-dark) 100%);\n  }\n}\n\n.header-inner {\n  max-width: 1248px;\n  margin: 0 auto;\n  padding: 0.75rem 1rem;\n  display: flex;\n  align-items: center;\n  min-height: 3.5rem;\n}\n\n.brand {\n  display: flex;\n  align-items: center;\n  gap: 0.85rem;\n  color: #fff;\n  text-decoration: none;\n}\n.brand:hover {\n  text-decoration: none;\n  filter: brightness(1.05);\n}\n\n.brand-mark {\n  width: 2.5rem;\n  height: 2.5rem;\n  border-radius: 50%;\n  background: radial-gradient(circle at 30% 25%, var(--orange-hot), var(--orange) 45%, #9b2300 100%);\n  flex-shrink: 0;\n  box-shadow: 0 0 0 3px rgba(255, 69, 0, 0.35), inset 0 2px 4px rgba(255, 255, 255, 0.35);\n}\n\n.brand-text {\n  display: flex;\n  flex-direction: column;\n  gap: 0.1rem;\n  line-height: 1.2;\n}\n\n.brand-name {\n  font-family: var(--font-brand);\n  font-weight: 800;\n  font-size: 1.28rem;\n  letter-spacing: -0.03em;\n  color: #fff;\n  text-shadow: 0 1px 2px rgba(0, 0, 0, 0.35);\n}\n\n.brand-sub {\n  font-size: 0.78rem;\n  color: #b7bdc2;\n  font-weight: 500;\n}\n\n/* —— Subreddit / sort strip —— */\n.community-strip {\n  background: linear-gradient(180deg, #e8eaed 0%, #dfe3e8 100%);\n  border-bottom: 1px solid var(--border-strong);\n  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.7);\n}\n\n@media (prefers-color-scheme: dark) {\n  .community-strip {\n    background: linear-gradient(180deg, #1f1f20 0%, #161617 100%);\n    border-bottom-color: var(--border);\n    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);\n  }\n}\n\n.community-strip-inner {\n  max-width: 1248px;\n  margin: 0 auto;\n  padding: 0.45rem 1rem;\n  display: flex;\n  align-items: center;\n  gap: 0.45rem;\n  flex-wrap: wrap;\n  row-gap: 0.35rem;\n  font-size: 0.8rem;\n  font-weight: 600;\n  color: var(--meta);\n}\n\n/* 우아한빅토리 · 스튜디오 — 한 덩어리로 붙여서 줄바꿈 시에도 떨어지지 않게 */\n.community-crumb {\n  display: inline-flex;\n  align-items: center;\n  flex-wrap: nowrap;\n  gap: 0.28rem;\n  white-space: nowrap;\n}\n\n.community-crumb .crumb-sep {\n  margin: 0;\n  flex-shrink: 0;\n}\n\n.sort-pill {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  min-height: 28px;\n  padding: 0 0.65rem;\n  border-radius: 999px;\n  background: var(--card);\n  border: 1px solid var(--border-strong);\n  color: var(--meta);\n  box-shadow: var(--shadow-sm);\n}\n\n.sort-pill.is-on {\n  background: var(--orange);\n  border-color: var(--orange);\n  color: #fff;\n  box-shadow: 0 2px 8px rgba(255, 69, 0, 0.45);\n}\n\n.community-dot {\n  color: var(--border-strong);\n  font-weight: 400;\n  margin: 0 0.1rem;\n  user-select: none;\n}\n\n.community-name-ko {\n  color: var(--orange);\n  font-weight: 800;\n  font-family: var(--font);\n}\n\n.community-tagline {\n  color: var(--meta);\n  font-weight: 600;\n  word-break: keep-all;\n}\n\n@media (prefers-color-scheme: dark) {\n  .sort-pill {\n    background: #2a2a2b;\n    border-color: #3d3d3e;\n    color: #b7bdc2;\n  }\n}\n\n/* —— Body shell: 항상 「좌측 메뉴 열 + 본문」 (좁은 화면은 메뉴 열 폭만 줄임) —— */\n.body-shell {\n  max-width: 1248px;\n  margin: 0 auto;\n  padding: 0.85rem 0.85rem 2.25rem;\n  display: grid;\n  grid-template-columns: minmax(200px, 220px) minmax(0, 1fr);\n  gap: 1rem;\n  align-items: start;\n}\n\n/* 태블릿·모바일도 2열 유지: 메뉴는 왼쪽 세로 리스트 */\n@media (max-width: 960px) {\n  .body-shell {\n    grid-template-columns: minmax(132px, 34vw) minmax(0, 1fr);\n    gap: 0.65rem;\n    padding: 0.55rem 0.45rem 1.75rem;\n  }\n}\n\n/* 극소 화면: 메뉴를 위에 전체 너비 세로로 두고, 본문은 아래(여전히 왼쪽 정렬 리스트) */\n@media (max-width: 380px) {\n  .body-shell {\n    grid-template-columns: 1fr;\n    padding: 0.4rem 0.4rem 1.5rem;\n  }\n}\n\n.layout-main {\n  min-width: 0;\n}\n\n.left-nav {\n  background: var(--card);\n  border: 1px solid var(--border);\n  border-radius: var(--radius-card);\n  padding: 0.5rem 0;\n  box-shadow: var(--shadow-card);\n  position: sticky;\n  top: 4.85rem;\n  z-index: 40;\n  align-self: start;\n  border-right: 3px solid rgba(255, 69, 0, 0.2);\n}\n\n@media (max-width: 380px) {\n  .left-nav {\n    position: static;\n    top: auto;\n    margin-bottom: 0.65rem;\n    border-right: 1px solid var(--border);\n    border-bottom: 3px solid rgba(255, 69, 0, 0.25);\n  }\n}\n\n.left-nav-heading {\n  margin: 0 0 0.25rem;\n  padding: 0 0.85rem 0.45rem;\n  font-size: 0.65rem;\n  font-weight: 800;\n  text-transform: uppercase;\n  letter-spacing: 0.1em;\n  color: var(--meta);\n  border-bottom: 1px solid var(--border);\n}\n\n@media (max-width: 960px) {\n  .left-nav-heading {\n    padding-left: 0.55rem;\n    padding-right: 0.45rem;\n    font-size: 0.6rem;\n  }\n}\n\n.nav-item {\n  display: flex;\n  align-items: flex-start;\n  gap: 0.45rem;\n  padding: 0.58rem 0.75rem;\n  color: var(--text);\n  font-weight: 600;\n  font-size: 0.9rem;\n  text-decoration: none;\n  border-left: 3px solid transparent;\n  transition: background 0.12s ease, border-color 0.12s ease;\n}\n\n.nav-item:hover {\n  background: var(--canvas);\n  text-decoration: none;\n}\n\n.nav-item.is-active {\n  border-left-color: var(--orange);\n  background: rgba(255, 69, 0, 0.1);\n  font-weight: 800;\n}\n\n@media (prefers-color-scheme: dark) {\n  .nav-item.is-active {\n    background: rgba(255, 69, 0, 0.14);\n  }\n}\n\n@media (max-width: 960px) {\n  .nav-item {\n    padding: 0.5rem 0.5rem;\n    font-size: 0.78rem;\n    gap: 0.35rem;\n  }\n}\n\n@media (max-width: 380px) {\n  .nav-item {\n    font-size: 0.85rem;\n    padding: 0.55rem 0.85rem;\n  }\n}\n\n.nav-icon {\n  width: 1.25rem;\n  text-align: center;\n  font-size: 1.05rem;\n  line-height: 1;\n  opacity: 0.9;\n}\n\n.nav-label {\n  line-height: 1.3;\n  word-break: keep-all;\n  overflow-wrap: break-word;\n}\n\n/* —— Main two-column (feed + right sidebar) —— */\n.page-wrap {\n  margin: 0;\n  padding: 0;\n  display: grid;\n  grid-template-columns: minmax(0, 1fr) 280px;\n  gap: 1.15rem;\n  align-items: start;\n}\n\n@media (max-width: 960px) {\n  .page-wrap {\n    grid-template-columns: 1fr;\n  }\n}\n\n/* —— Standalone placeholder page (브리핑 등) —— */\n.placeholder-page {\n  min-width: 0;\n}\n\n.placeholder-hero {\n  background: var(--card);\n  border: 1px solid var(--border);\n  border-radius: var(--radius-card);\n  padding: 1.35rem 1.25rem 1.5rem;\n  box-shadow: var(--shadow-card);\n  border-top: 4px solid var(--orange);\n}\n\n.placeholder-hero h1 {\n  margin: 0 0 0.5rem;\n  font-family: var(--font-brand);\n  font-size: 1.35rem;\n  font-weight: 800;\n  letter-spacing: -0.02em;\n}\n\n.placeholder-hero .lede {\n  margin: 0;\n  font-size: 0.95rem;\n  color: var(--meta);\n  line-height: 1.55;\n}\n\n.placeholder-badge {\n  display: inline-block;\n  margin-bottom: 0.65rem;\n  padding: 0.2rem 0.55rem;\n  border-radius: 999px;\n  font-size: 0.65rem;\n  font-weight: 800;\n  text-transform: uppercase;\n  letter-spacing: 0.06em;\n  background: rgba(255, 69, 0, 0.12);\n  border: 1px solid rgba(255, 69, 0, 0.35);\n  color: var(--orange);\n}\n\n.feed-column {\n  min-width: 0;\n}\n\n.sidebar {\n  min-width: 0;\n}\n\n@media (max-width: 960px) {\n  .sidebar {\n    order: 3;\n  }\n}\n\n/* —— Section titles —— */\n.section-title {\n  margin: 1.15rem 0 0.55rem;\n  padding-left: 0.65rem;\n  border-left: 4px solid var(--orange);\n  font-size: 0.7rem;\n  font-weight: 800;\n  text-transform: uppercase;\n  letter-spacing: 0.12em;\n  color: var(--meta);\n  line-height: 1.2;\n}\n\n.section-title:first-of-type {\n  margin-top: 0;\n}\n\n/* —— Composer (create post) —— */\n.create-card {\n  position: relative;\n  background: var(--card);\n  border: 1px solid var(--border);\n  border-radius: var(--radius-card);\n  padding: 1rem 1.1rem 1.1rem;\n  margin-bottom: 0.85rem;\n  box-shadow: var(--shadow-card);\n  border-top: 4px solid var(--orange);\n}\n\n.create-card::before {\n  content: "글쓰기";\n  position: absolute;\n  top: 0.65rem;\n  right: 1rem;\n  font-size: 0.65rem;\n  font-weight: 800;\n  text-transform: uppercase;\n  letter-spacing: 0.08em;\n  color: var(--orange);\n  opacity: 0.85;\n}\n\n.create-card label {\n  display: block;\n  font-size: 0.7rem;\n  font-weight: 800;\n  text-transform: uppercase;\n  letter-spacing: 0.06em;\n  color: var(--meta);\n  margin-bottom: 0.4rem;\n}\n\n.field-row {\n  display: grid;\n  grid-template-columns: 1fr 1fr;\n  gap: 0.85rem;\n  margin-top: 0.85rem;\n}\n\n@media (max-width: 560px) {\n  .field-row {\n    grid-template-columns: 1fr;\n  }\n}\n\ninput[type="text"],\nselect,\ntextarea {\n  width: 100%;\n  padding: 0.7rem 0.85rem;\n  border: 2px solid var(--border-strong);\n  border-radius: var(--radius);\n  font: inherit;\n  font-size: 16px;\n  background: var(--card);\n  color: var(--text);\n  transition: border-color 0.15s ease, box-shadow 0.15s ease;\n}\n\ninput[type="text"]:focus,\nselect:focus,\ntextarea:focus {\n  outline: none;\n  border-color: var(--orange);\n  box-shadow: 0 0 0 3px rgba(255, 69, 0, 0.2);\n}\n\n/* —— Actions —— */\n.action-bar {\n  display: flex;\n  flex-wrap: nowrap;\n  gap: 0.55rem;\n  margin-top: 1rem;\n  padding: 0.15rem 0 0.2rem;\n  overflow-x: auto;\n  -webkit-overflow-scrolling: touch;\n  scrollbar-width: thin;\n}\n\n.action-bar::-webkit-scrollbar {\n  height: 5px;\n}\n\n.action-bar::-webkit-scrollbar-thumb {\n  background: var(--border-strong);\n  border-radius: 4px;\n}\n\n.action-bar button {\n  flex: 0 0 auto;\n  min-height: var(--tap-min);\n  padding: 0 1.1rem;\n  border-radius: 999px;\n  font: inherit;\n  font-size: 0.9rem;\n  font-weight: 800;\n  cursor: pointer;\n  border: 2px solid transparent;\n  white-space: nowrap;\n  transition: transform 0.12s ease, box-shadow 0.12s ease;\n}\n\n.action-bar button:active {\n  transform: scale(0.97);\n}\n\n.btn-secondary {\n  background: var(--card);\n  border-color: var(--border-strong);\n  color: var(--text);\n  box-shadow: var(--shadow-sm);\n}\n\n.btn-secondary:hover {\n  background: var(--canvas);\n  border-color: var(--meta);\n}\n\n.btn-primary {\n  background: linear-gradient(180deg, var(--orange-hot) 0%, var(--orange) 100%);\n  color: #fff;\n  border-color: #c73a00;\n  box-shadow: 0 3px 12px rgba(255, 69, 0, 0.45), inset 0 1px 0 rgba(255, 255, 255, 0.25);\n}\n\n.btn-primary:hover {\n  background: linear-gradient(180deg, #ff7a45 0%, var(--orange-hot) 100%);\n  box-shadow: 0 5px 18px rgba(255, 69, 0, 0.5);\n}\n\nbutton:disabled {\n  opacity: 0.5;\n  cursor: not-allowed;\n}\n\n#status {\n  margin-top: 0.75rem;\n  font-size: 0.9rem;\n  min-height: 1.3rem;\n  font-weight: 600;\n}\n\n.err {\n  color: var(--orange);\n}\n\n.ok {\n  color: #0a8f2d;\n}\n\n@media (prefers-color-scheme: dark) {\n  .ok {\n    color: #55bd46;\n  }\n}\n\n.muted {\n  color: var(--meta);\n  font-size: 0.9rem;\n}\n\n/* —— Feed —— */\n.feed-list {\n  display: flex;\n  flex-direction: column;\n  gap: 0.75rem;\n}\n\n.feed-post {\n  display: flex;\n  background: var(--card);\n  border: 1px solid var(--border);\n  border-radius: var(--radius-card);\n  overflow: hidden;\n  box-shadow: var(--shadow-card);\n  transition: box-shadow 0.2s ease, transform 0.2s ease;\n}\n\n.feed-post:hover {\n  box-shadow: var(--shadow-card-hover);\n  transform: translateY(-2px);\n}\n\n.post-rail {\n  width: 2.85rem;\n  flex-shrink: 0;\n  background: linear-gradient(180deg, rgba(255, 69, 0, 0.12) 0%, var(--canvas) 55%);\n  border-right: 1px solid var(--border);\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  padding: 0.65rem 0.3rem;\n}\n\n.post-rank-num {\n  font-size: 0.75rem;\n  font-weight: 900;\n  color: var(--orange);\n  line-height: 1;\n}\n\n.post-main {\n  flex: 1;\n  min-width: 0;\n  padding: 0.75rem 1rem 0.9rem;\n}\n\n.post-title {\n  margin: 0 0 0.4rem;\n  font-size: 1.08rem;\n  font-weight: 700;\n  line-height: 1.35;\n}\n\n.post-title a {\n  color: var(--text);\n}\n.post-title a:hover {\n  color: var(--link);\n  text-decoration: none;\n}\n\n.post-meta {\n  font-size: 0.78rem;\n  color: var(--meta);\n  margin-bottom: 0.55rem;\n  display: flex;\n  flex-wrap: wrap;\n  gap: 0.4rem;\n  align-items: center;\n}\n\n.flair {\n  display: inline-block;\n  padding: 0.15rem 0.5rem;\n  border-radius: 999px;\n  background: rgba(255, 69, 0, 0.1);\n  border: 1px solid rgba(255, 69, 0, 0.35);\n  font-size: 0.62rem;\n  font-weight: 800;\n  text-transform: uppercase;\n  letter-spacing: 0.04em;\n  color: var(--orange);\n}\n\n@media (prefers-color-scheme: dark) {\n  .flair {\n    background: rgba(255, 69, 0, 0.15);\n  }\n}\n\n.post-excerpt {\n  margin: 0;\n  font-size: 0.9rem;\n  color: var(--text);\n  line-height: 1.5;\n  display: -webkit-box;\n  -webkit-line-clamp: 4;\n  -webkit-box-orient: vertical;\n  overflow: hidden;\n}\n\n.post-footer-link {\n  display: inline-block;\n  margin-top: 0.55rem;\n  font-size: 0.82rem;\n  font-weight: 800;\n}\n\n.empty-feed {\n  background: var(--card);\n  border: 2px dashed var(--border-strong);\n  border-radius: var(--radius-card);\n  padding: 2.25rem 1.25rem;\n  text-align: center;\n  color: var(--meta);\n  font-size: 0.95rem;\n  font-weight: 600;\n  box-shadow: var(--shadow-sm);\n}\n\n/* —— Sidebar —— */\n.widget {\n  background: var(--card);\n  border: 1px solid var(--border);\n  border-radius: var(--radius-card);\n  padding: 0.95rem;\n  margin-bottom: 0.85rem;\n  box-shadow: var(--shadow-card);\n}\n\n.widget .section-title {\n  margin: 0 0 0.75rem;\n  padding-left: 0.55rem;\n  border-left-width: 3px;\n}\n\n.insight-item {\n  padding: 0.55rem 0;\n  border-bottom: 1px solid var(--border);\n  font-size: 0.88rem;\n}\n.insight-item:last-child {\n  border-bottom: none;\n}\n\n.insight-item strong {\n  display: block;\n  margin-bottom: 0.25rem;\n  line-height: 1.35;\n}\n\n.analysis-block {\n  margin-bottom: 1.1rem;\n  padding-bottom: 1.1rem;\n  border-bottom: 1px solid var(--border);\n}\n.analysis-block:last-child {\n  margin-bottom: 0;\n  padding-bottom: 0;\n  border-bottom: none;\n}\n\npre.out {\n  white-space: pre-wrap;\n  word-break: break-word;\n  font-size: 0.82rem;\n  line-height: 1.55;\n  max-height: min(52vh, 440px);\n  overflow: auto;\n  background: var(--canvas);\n  padding: 1rem;\n  border-radius: var(--radius);\n  border: 1px solid var(--border);\n  margin: 0;\n  font-family: ui-monospace, "Cascadia Code", "Source Code Pro", Menlo, Consolas, monospace;\n}\n\n#summary {\n  font-size: 0.9rem;\n  line-height: 1.6;\n}\n\n    </style>\n  </head>\n  <body>\n    <header class="site-header">\n      <div class="header-inner">\n        <a href="/" class="brand">\n          <span class="brand-mark" aria-hidden="true"></span>\n          <span class="brand-text">\n            <span class="brand-name">우아한빅토리 스튜디오</span>\n            <span class="brand-sub">검색 · 분석 · 초안 · 한 화면에서</span>\n          </span>\n        </a>\n      </div>\n    </header>\n\n    <div class="community-strip" aria-hidden="true">\n      <div class="community-strip-inner">\n        <span class="sort-pill is-on">BEST</span>\n        <span class="sort-pill">HOT</span>\n        <span class="sort-pill">NEW</span>\n        <span class="community-dot" aria-hidden="true">·</span>\n        <span class="community-crumb" translate="no">\n          <strong class="community-name-ko">우아한빅토리</strong>\n          <span class="community-dot crumb-sep" aria-hidden="true">·</span>\n          <span class="community-tagline">스튜디오</span>\n        </span>\n      </div>\n    </div>\n\n    <div class="body-shell">\n      <nav class="left-nav" aria-label="주요 메뉴">\n        <p class="left-nav-heading">탐색</p>\n        <a href="/" class="nav-item is-active">\n          <span class="nav-icon" aria-hidden="true">⌂</span>\n          <span class="nav-label">인기 블로그 분석 및 요약</span>\n        </a>\n        <a href="/economy-briefing" class="nav-item">\n          <span class="nav-icon" aria-hidden="true">▤</span>\n          <span class="nav-label">경제 데일리 브리핑</span>\n        </a>\n        <a href="/weather-briefing" class="nav-item">\n          <span class="nav-icon" aria-hidden="true">☁</span>\n          <span class="nav-label">날씨 데일리 브리핑</span>\n        </a>\n      </nav>\n\n      <div class="layout-main">\n    <div class="page-wrap">\n      <div class="feed-column">\n        <div class="create-card">\n          <label for="keyword">키워드</label>\n          <input id="keyword" type="text" placeholder="예: 제주도 가족여행" autocomplete="off" />\n\n          <div class="field-row">\n            <div>\n              <label for="tone">생성 스타일</label>\n              <select id="tone">\n                <option value="전문가톤">전문가톤</option>\n                <option value="친근톤">친근톤</option>\n                <option value="브랜디드톤">브랜디드톤</option>\n              </select>\n            </div>\n            <div>\n              <label for="sort">검색 정렬</label>\n              <select id="sort">\n                <option value="sim">관련도순</option>\n                <option value="date">최신순</option>\n              </select>\n            </div>\n          </div>\n\n          <div class="action-bar">\n            <button type="button" class="btn-primary" id="btn-search">검색</button>\n            <button type="button" class="btn-secondary" id="btn-generate">생성</button>\n            <button type="button" class="btn-secondary" id="btn-summarize">요약</button>\n            <button type="button" class="btn-secondary" id="btn-images">이미지</button>\n            <button type="button" class="btn-secondary" id="btn-download">다운로드</button>\n          </div>\n          <div id="status" class="muted"></div>\n        </div>\n\n        <h2 class="section-title">피드</h2>\n        <div id="feed" class="feed-list"></div>\n\n        <h2 class="section-title">분석 결과</h2>\n        <div id="analysis" class="widget muted">생성·요약 실행 후 표시됩니다.</div>\n\n        <h2 class="section-title">생성된 초안</h2>\n        <div class="widget">\n          <pre class="out" id="draft">(없음)</pre>\n        </div>\n      </div>\n\n      <aside class="sidebar">\n        <div class="widget">\n          <h2 class="section-title">Trending</h2>\n          <div id="trending"></div>\n        </div>\n        <div class="widget">\n          <h2 class="section-title">Clear Thought 요약</h2>\n          <div id="summary" class="muted">요약 버튼으로 생성합니다.</div>\n        </div>\n      </aside>\n    </div>\n      </div>\n    </div>\n\n    <script type="module">\nconst $ = (id) => document.getElementById(id);\n\nconst state = {\n  results: [],\n  analyzed: [],\n  markdown: "",\n  images: [],\n};\n\nfunction setStatus(msg, isErr = false) {\n  const el = $("status");\n  el.textContent = msg;\n  el.className = isErr ? "err" : "ok";\n}\n\nasync function api(path, body) {\n  const res = await fetch(`/api${path}`, {\n    method: "POST",\n    headers: { "Content-Type": "application/json" },\n    body: JSON.stringify(body),\n  });\n  const data = await res.json().catch(() => ({}));\n  if (!res.ok) {\n    const detail = data.detail || data.message || JSON.stringify(data);\n    throw new Error(typeof detail === "string" ? detail : JSON.stringify(detail));\n  }\n  return data;\n}\n\nfunction renderFeed() {\n  const feed = $("feed");\n  if (!state.results.length) {\n    feed.innerHTML =\n      \'<div class="empty-feed">검색을 실행하면 네이버 블로그 결과가 여기에 나타납니다.</div>\';\n    return;\n  }\n  feed.innerHTML = state.results\n    .map((row, i) => {\n      const rank = row.ranking_basis || "관련도";\n      const author = [row.bloggername, row.postdate].filter(Boolean).join(" · ");\n      return `<article class="feed-post">\n        <div class="post-rail"><span class="post-rank-num">${i + 1}</span></div>\n        <div class="post-main">\n          <h3 class="post-title"><a href="${escAttr(row.link)}" target="_blank" rel="noopener">${esc(row.title)}</a></h3>\n          <div class="post-meta">\n            <span>${esc(author || "블로그")}</span>\n            <span class="flair">${esc(rank)}</span>\n          </div>\n          <p class="post-excerpt">${esc(row.description || "")}</p>\n          <a class="post-footer-link" href="${escAttr(row.link)}" target="_blank" rel="noopener">원문 보기</a>\n        </div>\n      </article>`;\n    })\n    .join("");\n}\n\nfunction esc(s) {\n  return String(s)\n    .replace(/&/g, "&amp;")\n    .replace(/</g, "&lt;")\n    .replace(/>/g, "&gt;")\n    .replace(/"/g, "&quot;");\n}\n\nfunction escAttr(s) {\n  return String(s).replace(/"/g, "&quot;");\n}\n\nfunction renderTrending() {\n  const el = $("trending");\n  if (!state.analyzed.length) {\n    el.innerHTML = \'<span class="muted">분석 후 키워드가 여기 표시됩니다.</span>\';\n    return;\n  }\n  el.innerHTML = state.analyzed\n    .slice(0, 5)\n    .map((row, i) => {\n      const k = (row.keywords || []).slice(0, 3).join(", ") || "키워드 없음";\n      return `<div class="insight-item"><strong>${i + 1}. ${esc((row.title || "").slice(0, 42))}</strong><div class="muted">${esc(k)}</div></div>`;\n    })\n    .join("");\n}\n\nfunction renderAnalysis() {\n  const el = $("analysis");\n  if (!state.analyzed.length) {\n    el.textContent = "생성·요약 실행 후 표시됩니다.";\n    el.className = "widget muted";\n    return;\n  }\n  el.className = "widget";\n  el.innerHTML = state.analyzed\n    .map(\n      (row, i) =>\n        `<div class="analysis-block">\n        <strong>${i + 1}. ${esc(row.title)}</strong>\n        <div class="muted" style="margin:0.25rem 0"><a href="${escAttr(row.link)}" target="_blank" rel="noopener">링크</a></div>\n        <div style="font-size:0.875rem">키워드: ${esc((row.keywords || []).join(", ") || "없음")}</div>\n        <div class="muted" style="margin-top:0.35rem;font-size:0.875rem">${esc((row.summary || "").slice(0, 400))}</div>\n        ${row.analysis_source === "description_fallback" ? \'<div class="muted" style="margin-top:0.35rem;font-size:0.8rem">※ description 대체 분석</div>\' : ""}\n        </div>`\n    )\n    .join("");\n}\n\nfunction renderDraft() {\n  $("draft").textContent = state.markdown || "(없음)";\n}\n\n$("btn-search").addEventListener("click", async () => {\n  const keyword = $("keyword").value.trim();\n  const sort = $("sort").value;\n  if (!keyword) {\n    setStatus("키워드를 입력하세요.", true);\n    return;\n  }\n  setStatus("검색 중…");\n  try {\n    const data = await api("/search", { keyword, sort });\n    state.results = data.results || [];\n    state.analyzed = [];\n    state.markdown = "";\n    state.images = [];\n    renderFeed();\n    renderTrending();\n    renderAnalysis();\n    renderDraft();\n    $("summary").textContent = "요약 버튼으로 생성합니다.";\n    setStatus(`완료 · ${state.results.length}건 · ${data.sort_label || ""}`);\n  } catch (e) {\n    setStatus(e.message, true);\n  }\n});\n\n$("btn-generate").addEventListener("click", async () => {\n  const keyword = $("keyword").value.trim();\n  const tone = $("tone").value;\n  if (!keyword) {\n    setStatus("키워드를 입력하세요.", true);\n    return;\n  }\n  if (!state.results.length) {\n    setStatus("먼저 검색 실행하세요.", true);\n    return;\n  }\n  setStatus("분석·생성 중…");\n  try {\n    const a = await api("/analyze", { results: state.results });\n    state.analyzed = a.analyzed || [];\n    const g = await api("/generate", { keyword, tone, analyzed: state.analyzed });\n    state.markdown = g.markdown || "";\n    state.images = [];\n    renderTrending();\n    renderAnalysis();\n    renderDraft();\n    setStatus("생성 완료");\n  } catch (e) {\n    setStatus(e.message, true);\n  }\n});\n\n$("btn-summarize").addEventListener("click", async () => {\n  const keyword = $("keyword").value.trim();\n  if (!keyword) {\n    setStatus("키워드를 입력하세요.", true);\n    return;\n  }\n  if (!state.results.length) {\n    setStatus("먼저 검색 실행하세요.", true);\n    return;\n  }\n  setStatus("요약 중…");\n  try {\n    const a = await api("/analyze", { results: state.results });\n    state.analyzed = a.analyzed || [];\n    const s = await api("/summarize", { keyword, analyzed: state.analyzed });\n    $("summary").innerHTML = markedLight(s.summary || "");\n    renderTrending();\n    renderAnalysis();\n    setStatus("요약 완료");\n  } catch (e) {\n    setStatus(e.message, true);\n  }\n});\n\nfunction markedLight(md) {\n  return esc(md).replace(/\\n/g, "<br/>");\n}\n\n$("btn-images").addEventListener("click", async () => {\n  const keyword = $("keyword").value.trim();\n  if (!state.markdown) {\n    setStatus("먼저 생성하기로 글을 만드세요.", true);\n    return;\n  }\n  setStatus("이미지 생성 중…");\n  try {\n    const data = await api("/images", { keyword: keyword || "블로그", markdown: state.markdown });\n    state.markdown = data.markdown || state.markdown;\n    state.images = data.images || [];\n    renderDraft();\n    setStatus(`이미지 삽입 완료 · Replicate 설정: ${data.replicate_configured}`);\n  } catch (e) {\n    setStatus(e.message, true);\n  }\n});\n\n$("btn-download").addEventListener("click", async () => {\n  if (!state.markdown) {\n    setStatus("저장할 초안이 없습니다.", true);\n    return;\n  }\n  const keyword = $("keyword").value.trim() || "blog";\n  const safe = keyword.replace(/[^가-힣A-Za-z0-9_-]/g, "_");\n  const stamp = new Date().toISOString().slice(0, 19).replace(/[:T]/g, "");\n\n  const { default: JSZip } = await import("https://esm.sh/jszip@3.10.1");\n  const zip = new JSZip();\n  let md = state.markdown;\n  (state.images || []).forEach((img, i) => {\n    const name = img.filename || `image_${i + 1}.png`;\n    const bin = Uint8Array.from(atob(img.content_base64 || ""), (c) => c.charCodeAt(0));\n    zip.file(name, bin);\n    md = md.replace(new RegExp(`!\\\\[생성 이미지 ${i + 1}\\\\]\\\\([^)]*\\\\)`, "g"), `![생성 이미지 ${i + 1}](${name})`);\n  });\n  zip.file(`${safe}.md`, md);\n  const blob = await zip.generateAsync({ type: "blob" });\n  const a = document.createElement("a");\n  a.href = URL.createObjectURL(blob);\n  a.download = `${safe}_${stamp}.zip`;\n  a.click();\n  URL.revokeObjectURL(a.href);\n  setStatus("ZIP 다운로드 시작됨");\n});\n\nrenderFeed();\nrenderTrending();\nrenderDraft();\n\n    </script>\n  </body>\n</html>\n'

ECONOMY_BRIEFING_HTML = '<!DOCTYPE html>\n<html lang="ko">\n  <head>\n    <meta charset="utf-8" />\n    <meta name="viewport" content="width=device-width, initial-scale=1, viewport-fit=cover" />\n    <meta name="color-scheme" content="light dark" />\n    <meta name="theme-color" content="#1a1a1a" />\n    <title>경제 데일리 브리핑 · 우아한빅토리 스튜디오</title>\n    <link rel="preconnect" href="https://fonts.googleapis.com" />\n    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin />\n    <link\n      href="https://fonts.googleapis.com/css2?family=IBM+Plex+Sans:wght@400;600;700&family=Plus+Jakarta+Sans:wght@700;800&display=swap"\n      rel="stylesheet"\n    />\n    <style>\n/* Reddit-style: high-contrast header, orange accent, dotted canvas, lifted cards */\n:root {\n  --canvas: #c9ccd1;\n  --canvas-dot: rgba(0, 0, 0, 0.07);\n  --card: #ffffff;\n  --border: #e1e4e8;\n  --border-strong: #b7bcc4;\n  --text: #0f0f0f;\n  --meta: #5c5f62;\n  --link: #006cbf;\n  --orange: #ff4500;\n  --orange-hot: #ff6a33;\n  --orange-hover: #e03d00;\n  --header-dark: #1a1a1b;\n  --header-border: #343536;\n  --shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.06);\n  --shadow-card: 0 4px 14px rgba(0, 0, 0, 0.12), 0 0 0 1px rgba(0, 0, 0, 0.04);\n  --shadow-card-hover: 0 8px 24px rgba(0, 0, 0, 0.14), 0 0 0 1px rgba(255, 69, 0, 0.12);\n  --radius: 6px;\n  --radius-card: 10px;\n  --tap-min: 46px;\n  --font: "IBM Plex Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial,\n    "Apple SD Gothic Neo", "Noto Sans KR", sans-serif;\n  --font-brand: "Plus Jakarta Sans", var(--font);\n}\n\n@media (prefers-color-scheme: dark) {\n  :root {\n    --canvas: #030303;\n    --canvas-dot: rgba(255, 255, 255, 0.04);\n    --card: #1a1a1b;\n    --border: #343536;\n    --border-strong: #56585a;\n    --text: #d7dadc;\n    --meta: #9fa1a3;\n    --link: #58a6ff;\n    --orange: #ff4500;\n    --orange-hot: #ff7849;\n    --orange-hover: #ff6a33;\n    --header-dark: #0b0b0c;\n    --header-border: #1f1f1f;\n    --shadow-sm: 0 1px 3px rgba(0, 0, 0, 0.5);\n    --shadow-card: 0 4px 18px rgba(0, 0, 0, 0.55), 0 0 0 1px #2a2a2b;\n    --shadow-card-hover: 0 10px 28px rgba(0, 0, 0, 0.65), 0 0 0 1px rgba(255, 69, 0, 0.35);\n  }\n}\n\n* {\n  box-sizing: border-box;\n}\n\nhtml {\n  -webkit-text-size-adjust: 100%;\n}\n\nbody {\n  margin: 0;\n  min-height: 100dvh;\n  font-family: var(--font);\n  font-size: 15px;\n  background-color: var(--canvas);\n  background-image: radial-gradient(circle at 1px 1px, var(--canvas-dot) 1px, transparent 0);\n  background-size: 18px 18px;\n  color: var(--text);\n  line-height: 1.55;\n  padding-bottom: env(safe-area-inset-bottom, 0);\n}\n\na {\n  color: var(--link);\n  text-decoration: none;\n}\na:hover {\n  text-decoration: underline;\n}\n\n/* —— Top bar (dark, Reddit-app feel) —— */\n.site-header {\n  position: sticky;\n  top: 0;\n  z-index: 200;\n  background: linear-gradient(180deg, #252526 0%, var(--header-dark) 100%);\n  border-bottom: 3px solid var(--orange);\n  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.25);\n  padding-top: env(safe-area-inset-top, 0);\n}\n\n@media (prefers-color-scheme: dark) {\n  .site-header {\n    background: linear-gradient(180deg, #121213 0%, var(--header-dark) 100%);\n  }\n}\n\n.header-inner {\n  max-width: 1248px;\n  margin: 0 auto;\n  padding: 0.75rem 1rem;\n  display: flex;\n  align-items: center;\n  min-height: 3.5rem;\n}\n\n.brand {\n  display: flex;\n  align-items: center;\n  gap: 0.85rem;\n  color: #fff;\n  text-decoration: none;\n}\n.brand:hover {\n  text-decoration: none;\n  filter: brightness(1.05);\n}\n\n.brand-mark {\n  width: 2.5rem;\n  height: 2.5rem;\n  border-radius: 50%;\n  background: radial-gradient(circle at 30% 25%, var(--orange-hot), var(--orange) 45%, #9b2300 100%);\n  flex-shrink: 0;\n  box-shadow: 0 0 0 3px rgba(255, 69, 0, 0.35), inset 0 2px 4px rgba(255, 255, 255, 0.35);\n}\n\n.brand-text {\n  display: flex;\n  flex-direction: column;\n  gap: 0.1rem;\n  line-height: 1.2;\n}\n\n.brand-name {\n  font-family: var(--font-brand);\n  font-weight: 800;\n  font-size: 1.28rem;\n  letter-spacing: -0.03em;\n  color: #fff;\n  text-shadow: 0 1px 2px rgba(0, 0, 0, 0.35);\n}\n\n.brand-sub {\n  font-size: 0.78rem;\n  color: #b7bdc2;\n  font-weight: 500;\n}\n\n/* —— Subreddit / sort strip —— */\n.community-strip {\n  background: linear-gradient(180deg, #e8eaed 0%, #dfe3e8 100%);\n  border-bottom: 1px solid var(--border-strong);\n  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.7);\n}\n\n@media (prefers-color-scheme: dark) {\n  .community-strip {\n    background: linear-gradient(180deg, #1f1f20 0%, #161617 100%);\n    border-bottom-color: var(--border);\n    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);\n  }\n}\n\n.community-strip-inner {\n  max-width: 1248px;\n  margin: 0 auto;\n  padding: 0.45rem 1rem;\n  display: flex;\n  align-items: center;\n  gap: 0.45rem;\n  flex-wrap: wrap;\n  row-gap: 0.35rem;\n  font-size: 0.8rem;\n  font-weight: 600;\n  color: var(--meta);\n}\n\n/* 우아한빅토리 · 스튜디오 — 한 덩어리로 붙여서 줄바꿈 시에도 떨어지지 않게 */\n.community-crumb {\n  display: inline-flex;\n  align-items: center;\n  flex-wrap: nowrap;\n  gap: 0.28rem;\n  white-space: nowrap;\n}\n\n.community-crumb .crumb-sep {\n  margin: 0;\n  flex-shrink: 0;\n}\n\n.sort-pill {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  min-height: 28px;\n  padding: 0 0.65rem;\n  border-radius: 999px;\n  background: var(--card);\n  border: 1px solid var(--border-strong);\n  color: var(--meta);\n  box-shadow: var(--shadow-sm);\n}\n\n.sort-pill.is-on {\n  background: var(--orange);\n  border-color: var(--orange);\n  color: #fff;\n  box-shadow: 0 2px 8px rgba(255, 69, 0, 0.45);\n}\n\n.community-dot {\n  color: var(--border-strong);\n  font-weight: 400;\n  margin: 0 0.1rem;\n  user-select: none;\n}\n\n.community-name-ko {\n  color: var(--orange);\n  font-weight: 800;\n  font-family: var(--font);\n}\n\n.community-tagline {\n  color: var(--meta);\n  font-weight: 600;\n  word-break: keep-all;\n}\n\n@media (prefers-color-scheme: dark) {\n  .sort-pill {\n    background: #2a2a2b;\n    border-color: #3d3d3e;\n    color: #b7bdc2;\n  }\n}\n\n/* —— Body shell: 항상 「좌측 메뉴 열 + 본문」 (좁은 화면은 메뉴 열 폭만 줄임) —— */\n.body-shell {\n  max-width: 1248px;\n  margin: 0 auto;\n  padding: 0.85rem 0.85rem 2.25rem;\n  display: grid;\n  grid-template-columns: minmax(200px, 220px) minmax(0, 1fr);\n  gap: 1rem;\n  align-items: start;\n}\n\n/* 태블릿·모바일도 2열 유지: 메뉴는 왼쪽 세로 리스트 */\n@media (max-width: 960px) {\n  .body-shell {\n    grid-template-columns: minmax(132px, 34vw) minmax(0, 1fr);\n    gap: 0.65rem;\n    padding: 0.55rem 0.45rem 1.75rem;\n  }\n}\n\n/* 극소 화면: 메뉴를 위에 전체 너비 세로로 두고, 본문은 아래(여전히 왼쪽 정렬 리스트) */\n@media (max-width: 380px) {\n  .body-shell {\n    grid-template-columns: 1fr;\n    padding: 0.4rem 0.4rem 1.5rem;\n  }\n}\n\n.layout-main {\n  min-width: 0;\n}\n\n.left-nav {\n  background: var(--card);\n  border: 1px solid var(--border);\n  border-radius: var(--radius-card);\n  padding: 0.5rem 0;\n  box-shadow: var(--shadow-card);\n  position: sticky;\n  top: 4.85rem;\n  z-index: 40;\n  align-self: start;\n  border-right: 3px solid rgba(255, 69, 0, 0.2);\n}\n\n@media (max-width: 380px) {\n  .left-nav {\n    position: static;\n    top: auto;\n    margin-bottom: 0.65rem;\n    border-right: 1px solid var(--border);\n    border-bottom: 3px solid rgba(255, 69, 0, 0.25);\n  }\n}\n\n.left-nav-heading {\n  margin: 0 0 0.25rem;\n  padding: 0 0.85rem 0.45rem;\n  font-size: 0.65rem;\n  font-weight: 800;\n  text-transform: uppercase;\n  letter-spacing: 0.1em;\n  color: var(--meta);\n  border-bottom: 1px solid var(--border);\n}\n\n@media (max-width: 960px) {\n  .left-nav-heading {\n    padding-left: 0.55rem;\n    padding-right: 0.45rem;\n    font-size: 0.6rem;\n  }\n}\n\n.nav-item {\n  display: flex;\n  align-items: flex-start;\n  gap: 0.45rem;\n  padding: 0.58rem 0.75rem;\n  color: var(--text);\n  font-weight: 600;\n  font-size: 0.9rem;\n  text-decoration: none;\n  border-left: 3px solid transparent;\n  transition: background 0.12s ease, border-color 0.12s ease;\n}\n\n.nav-item:hover {\n  background: var(--canvas);\n  text-decoration: none;\n}\n\n.nav-item.is-active {\n  border-left-color: var(--orange);\n  background: rgba(255, 69, 0, 0.1);\n  font-weight: 800;\n}\n\n@media (prefers-color-scheme: dark) {\n  .nav-item.is-active {\n    background: rgba(255, 69, 0, 0.14);\n  }\n}\n\n@media (max-width: 960px) {\n  .nav-item {\n    padding: 0.5rem 0.5rem;\n    font-size: 0.78rem;\n    gap: 0.35rem;\n  }\n}\n\n@media (max-width: 380px) {\n  .nav-item {\n    font-size: 0.85rem;\n    padding: 0.55rem 0.85rem;\n  }\n}\n\n.nav-icon {\n  width: 1.25rem;\n  text-align: center;\n  font-size: 1.05rem;\n  line-height: 1;\n  opacity: 0.9;\n}\n\n.nav-label {\n  line-height: 1.3;\n  word-break: keep-all;\n  overflow-wrap: break-word;\n}\n\n/* —— Main two-column (feed + right sidebar) —— */\n.page-wrap {\n  margin: 0;\n  padding: 0;\n  display: grid;\n  grid-template-columns: minmax(0, 1fr) 280px;\n  gap: 1.15rem;\n  align-items: start;\n}\n\n@media (max-width: 960px) {\n  .page-wrap {\n    grid-template-columns: 1fr;\n  }\n}\n\n/* —— Standalone placeholder page (브리핑 등) —— */\n.placeholder-page {\n  min-width: 0;\n}\n\n.placeholder-hero {\n  background: var(--card);\n  border: 1px solid var(--border);\n  border-radius: var(--radius-card);\n  padding: 1.35rem 1.25rem 1.5rem;\n  box-shadow: var(--shadow-card);\n  border-top: 4px solid var(--orange);\n}\n\n.placeholder-hero h1 {\n  margin: 0 0 0.5rem;\n  font-family: var(--font-brand);\n  font-size: 1.35rem;\n  font-weight: 800;\n  letter-spacing: -0.02em;\n}\n\n.placeholder-hero .lede {\n  margin: 0;\n  font-size: 0.95rem;\n  color: var(--meta);\n  line-height: 1.55;\n}\n\n.placeholder-badge {\n  display: inline-block;\n  margin-bottom: 0.65rem;\n  padding: 0.2rem 0.55rem;\n  border-radius: 999px;\n  font-size: 0.65rem;\n  font-weight: 800;\n  text-transform: uppercase;\n  letter-spacing: 0.06em;\n  background: rgba(255, 69, 0, 0.12);\n  border: 1px solid rgba(255, 69, 0, 0.35);\n  color: var(--orange);\n}\n\n.feed-column {\n  min-width: 0;\n}\n\n.sidebar {\n  min-width: 0;\n}\n\n@media (max-width: 960px) {\n  .sidebar {\n    order: 3;\n  }\n}\n\n/* —— Section titles —— */\n.section-title {\n  margin: 1.15rem 0 0.55rem;\n  padding-left: 0.65rem;\n  border-left: 4px solid var(--orange);\n  font-size: 0.7rem;\n  font-weight: 800;\n  text-transform: uppercase;\n  letter-spacing: 0.12em;\n  color: var(--meta);\n  line-height: 1.2;\n}\n\n.section-title:first-of-type {\n  margin-top: 0;\n}\n\n/* —— Composer (create post) —— */\n.create-card {\n  position: relative;\n  background: var(--card);\n  border: 1px solid var(--border);\n  border-radius: var(--radius-card);\n  padding: 1rem 1.1rem 1.1rem;\n  margin-bottom: 0.85rem;\n  box-shadow: var(--shadow-card);\n  border-top: 4px solid var(--orange);\n}\n\n.create-card::before {\n  content: "글쓰기";\n  position: absolute;\n  top: 0.65rem;\n  right: 1rem;\n  font-size: 0.65rem;\n  font-weight: 800;\n  text-transform: uppercase;\n  letter-spacing: 0.08em;\n  color: var(--orange);\n  opacity: 0.85;\n}\n\n.create-card label {\n  display: block;\n  font-size: 0.7rem;\n  font-weight: 800;\n  text-transform: uppercase;\n  letter-spacing: 0.06em;\n  color: var(--meta);\n  margin-bottom: 0.4rem;\n}\n\n.field-row {\n  display: grid;\n  grid-template-columns: 1fr 1fr;\n  gap: 0.85rem;\n  margin-top: 0.85rem;\n}\n\n@media (max-width: 560px) {\n  .field-row {\n    grid-template-columns: 1fr;\n  }\n}\n\ninput[type="text"],\nselect,\ntextarea {\n  width: 100%;\n  padding: 0.7rem 0.85rem;\n  border: 2px solid var(--border-strong);\n  border-radius: var(--radius);\n  font: inherit;\n  font-size: 16px;\n  background: var(--card);\n  color: var(--text);\n  transition: border-color 0.15s ease, box-shadow 0.15s ease;\n}\n\ninput[type="text"]:focus,\nselect:focus,\ntextarea:focus {\n  outline: none;\n  border-color: var(--orange);\n  box-shadow: 0 0 0 3px rgba(255, 69, 0, 0.2);\n}\n\n/* —— Actions —— */\n.action-bar {\n  display: flex;\n  flex-wrap: nowrap;\n  gap: 0.55rem;\n  margin-top: 1rem;\n  padding: 0.15rem 0 0.2rem;\n  overflow-x: auto;\n  -webkit-overflow-scrolling: touch;\n  scrollbar-width: thin;\n}\n\n.action-bar::-webkit-scrollbar {\n  height: 5px;\n}\n\n.action-bar::-webkit-scrollbar-thumb {\n  background: var(--border-strong);\n  border-radius: 4px;\n}\n\n.action-bar button {\n  flex: 0 0 auto;\n  min-height: var(--tap-min);\n  padding: 0 1.1rem;\n  border-radius: 999px;\n  font: inherit;\n  font-size: 0.9rem;\n  font-weight: 800;\n  cursor: pointer;\n  border: 2px solid transparent;\n  white-space: nowrap;\n  transition: transform 0.12s ease, box-shadow 0.12s ease;\n}\n\n.action-bar button:active {\n  transform: scale(0.97);\n}\n\n.btn-secondary {\n  background: var(--card);\n  border-color: var(--border-strong);\n  color: var(--text);\n  box-shadow: var(--shadow-sm);\n}\n\n.btn-secondary:hover {\n  background: var(--canvas);\n  border-color: var(--meta);\n}\n\n.btn-primary {\n  background: linear-gradient(180deg, var(--orange-hot) 0%, var(--orange) 100%);\n  color: #fff;\n  border-color: #c73a00;\n  box-shadow: 0 3px 12px rgba(255, 69, 0, 0.45), inset 0 1px 0 rgba(255, 255, 255, 0.25);\n}\n\n.btn-primary:hover {\n  background: linear-gradient(180deg, #ff7a45 0%, var(--orange-hot) 100%);\n  box-shadow: 0 5px 18px rgba(255, 69, 0, 0.5);\n}\n\nbutton:disabled {\n  opacity: 0.5;\n  cursor: not-allowed;\n}\n\n#status {\n  margin-top: 0.75rem;\n  font-size: 0.9rem;\n  min-height: 1.3rem;\n  font-weight: 600;\n}\n\n.err {\n  color: var(--orange);\n}\n\n.ok {\n  color: #0a8f2d;\n}\n\n@media (prefers-color-scheme: dark) {\n  .ok {\n    color: #55bd46;\n  }\n}\n\n.muted {\n  color: var(--meta);\n  font-size: 0.9rem;\n}\n\n/* —— Feed —— */\n.feed-list {\n  display: flex;\n  flex-direction: column;\n  gap: 0.75rem;\n}\n\n.feed-post {\n  display: flex;\n  background: var(--card);\n  border: 1px solid var(--border);\n  border-radius: var(--radius-card);\n  overflow: hidden;\n  box-shadow: var(--shadow-card);\n  transition: box-shadow 0.2s ease, transform 0.2s ease;\n}\n\n.feed-post:hover {\n  box-shadow: var(--shadow-card-hover);\n  transform: translateY(-2px);\n}\n\n.post-rail {\n  width: 2.85rem;\n  flex-shrink: 0;\n  background: linear-gradient(180deg, rgba(255, 69, 0, 0.12) 0%, var(--canvas) 55%);\n  border-right: 1px solid var(--border);\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  padding: 0.65rem 0.3rem;\n}\n\n.post-rank-num {\n  font-size: 0.75rem;\n  font-weight: 900;\n  color: var(--orange);\n  line-height: 1;\n}\n\n.post-main {\n  flex: 1;\n  min-width: 0;\n  padding: 0.75rem 1rem 0.9rem;\n}\n\n.post-title {\n  margin: 0 0 0.4rem;\n  font-size: 1.08rem;\n  font-weight: 700;\n  line-height: 1.35;\n}\n\n.post-title a {\n  color: var(--text);\n}\n.post-title a:hover {\n  color: var(--link);\n  text-decoration: none;\n}\n\n.post-meta {\n  font-size: 0.78rem;\n  color: var(--meta);\n  margin-bottom: 0.55rem;\n  display: flex;\n  flex-wrap: wrap;\n  gap: 0.4rem;\n  align-items: center;\n}\n\n.flair {\n  display: inline-block;\n  padding: 0.15rem 0.5rem;\n  border-radius: 999px;\n  background: rgba(255, 69, 0, 0.1);\n  border: 1px solid rgba(255, 69, 0, 0.35);\n  font-size: 0.62rem;\n  font-weight: 800;\n  text-transform: uppercase;\n  letter-spacing: 0.04em;\n  color: var(--orange);\n}\n\n@media (prefers-color-scheme: dark) {\n  .flair {\n    background: rgba(255, 69, 0, 0.15);\n  }\n}\n\n.post-excerpt {\n  margin: 0;\n  font-size: 0.9rem;\n  color: var(--text);\n  line-height: 1.5;\n  display: -webkit-box;\n  -webkit-line-clamp: 4;\n  -webkit-box-orient: vertical;\n  overflow: hidden;\n}\n\n.post-footer-link {\n  display: inline-block;\n  margin-top: 0.55rem;\n  font-size: 0.82rem;\n  font-weight: 800;\n}\n\n.empty-feed {\n  background: var(--card);\n  border: 2px dashed var(--border-strong);\n  border-radius: var(--radius-card);\n  padding: 2.25rem 1.25rem;\n  text-align: center;\n  color: var(--meta);\n  font-size: 0.95rem;\n  font-weight: 600;\n  box-shadow: var(--shadow-sm);\n}\n\n/* —— Sidebar —— */\n.widget {\n  background: var(--card);\n  border: 1px solid var(--border);\n  border-radius: var(--radius-card);\n  padding: 0.95rem;\n  margin-bottom: 0.85rem;\n  box-shadow: var(--shadow-card);\n}\n\n.widget .section-title {\n  margin: 0 0 0.75rem;\n  padding-left: 0.55rem;\n  border-left-width: 3px;\n}\n\n.insight-item {\n  padding: 0.55rem 0;\n  border-bottom: 1px solid var(--border);\n  font-size: 0.88rem;\n}\n.insight-item:last-child {\n  border-bottom: none;\n}\n\n.insight-item strong {\n  display: block;\n  margin-bottom: 0.25rem;\n  line-height: 1.35;\n}\n\n.analysis-block {\n  margin-bottom: 1.1rem;\n  padding-bottom: 1.1rem;\n  border-bottom: 1px solid var(--border);\n}\n.analysis-block:last-child {\n  margin-bottom: 0;\n  padding-bottom: 0;\n  border-bottom: none;\n}\n\npre.out {\n  white-space: pre-wrap;\n  word-break: break-word;\n  font-size: 0.82rem;\n  line-height: 1.55;\n  max-height: min(52vh, 440px);\n  overflow: auto;\n  background: var(--canvas);\n  padding: 1rem;\n  border-radius: var(--radius);\n  border: 1px solid var(--border);\n  margin: 0;\n  font-family: ui-monospace, "Cascadia Code", "Source Code Pro", Menlo, Consolas, monospace;\n}\n\n#summary {\n  font-size: 0.9rem;\n  line-height: 1.6;\n}\n\n    </style>\n  </head>\n  <body>\n    <header class="site-header">\n      <div class="header-inner">\n        <a href="/" class="brand">\n          <span class="brand-mark" aria-hidden="true"></span>\n          <span class="brand-text">\n            <span class="brand-name">우아한빅토리 스튜디오</span>\n            <span class="brand-sub">검색 · 분석 · 초안 · 한 화면에서</span>\n          </span>\n        </a>\n      </div>\n    </header>\n\n    <div class="community-strip" aria-hidden="true">\n      <div class="community-strip-inner">\n        <span class="sort-pill is-on">BEST</span>\n        <span class="sort-pill">HOT</span>\n        <span class="sort-pill">NEW</span>\n        <span class="community-dot" aria-hidden="true">·</span>\n        <span class="community-crumb" translate="no">\n          <strong class="community-name-ko">우아한빅토리</strong>\n          <span class="community-dot crumb-sep" aria-hidden="true">·</span>\n          <span class="community-tagline">스튜디오</span>\n        </span>\n      </div>\n    </div>\n\n    <div class="body-shell">\n      <nav class="left-nav" aria-label="주요 메뉴">\n        <p class="left-nav-heading">탐색</p>\n        <a href="/" class="nav-item">\n          <span class="nav-icon" aria-hidden="true">⌂</span>\n          <span class="nav-label">인기 블로그 분석 및 요약</span>\n        </a>\n        <a href="/economy-briefing" class="nav-item is-active">\n          <span class="nav-icon" aria-hidden="true">▤</span>\n          <span class="nav-label">경제 데일리 브리핑</span>\n        </a>\n        <a href="/weather-briefing" class="nav-item">\n          <span class="nav-icon" aria-hidden="true">☁</span>\n          <span class="nav-label">날씨 데일리 브리핑</span>\n        </a>\n      </nav>\n\n      <div class="layout-main">\n        <div class="page-wrap">\n          <div class="feed-column">\n            <div class="create-card">\n              <label for="economy-keyword">브리핑 키워드</label>\n              <input\n                id="economy-keyword"\n                type="text"\n                value="한국 금리 환율 증시"\n                placeholder="예: 미국 금리 인하, 반도체 수출, 환율"\n                autocomplete="off"\n              />\n\n              <div class="field-row">\n                <div>\n                  <label for="economy-sort">검색 정렬</label>\n                  <select id="economy-sort">\n                    <option value="date">최신순(date)</option>\n                    <option value="sim">관련도순(sim)</option>\n                  </select>\n                </div>\n                <div>\n                  <label for="economy-limit">브리핑 범위</label>\n                  <input id="economy-limit" type="text" value="최근 뉴스 12건" readonly />\n                </div>\n              </div>\n\n              <div class="action-bar">\n                <button type="button" class="btn-primary" id="btn-economy-search">뉴스 검색</button>\n                <button type="button" class="btn-secondary" id="btn-economy-briefing">브리핑 생성</button>\n              </div>\n              <div id="economy-status" class="muted"></div>\n            </div>\n\n            <h2 class="section-title">뉴스 피드</h2>\n            <div id="economy-feed" class="feed-list"></div>\n\n            <h2 class="section-title">오늘의 브리핑</h2>\n            <div class="widget">\n              <pre class="out" id="economy-briefing">(브리핑 없음)</pre>\n            </div>\n          </div>\n\n          <aside class="sidebar">\n            <div class="widget">\n              <h2 class="section-title">출처 분포</h2>\n              <div id="economy-signals" class="muted">뉴스 검색 후 집계됩니다.</div>\n            </div>\n            <div class="widget">\n              <h2 class="section-title">사용 안내</h2>\n              <div class="muted">\n                1) 뉴스 검색으로 최신 이슈를 모읍니다.<br />\n                2) 브리핑 생성을 누르면 핵심 키워드와 시사점이 정리됩니다.<br />\n                3) 키워드를 바꿔 테마별 브리핑을 반복 확인하세요.\n              </div>\n            </div>\n          </aside>\n        </div>\n      </div>\n    </div>\n\n    <script type="module">\n      const $ = (id) => document.getElementById(id);\n      const state = { results: [], briefing: "" };\n\n      function esc(value) {\n        return String(value)\n          .replace(/&/g, "&amp;")\n          .replace(/</g, "&lt;")\n          .replace(/>/g, "&gt;")\n          .replace(/"/g, "&quot;");\n      }\n\n      function escAttr(value) {\n        return String(value).replace(/"/g, "&quot;");\n      }\n\n      function setStatus(message, isErr = false) {\n        const el = $("economy-status");\n        el.textContent = message;\n        el.className = isErr ? "err" : "ok";\n      }\n\n      async function api(path, body) {\n        const res = await fetch(`/api${path}`, {\n          method: "POST",\n          headers: { "Content-Type": "application/json" },\n          body: JSON.stringify(body),\n        });\n        const data = await res.json().catch(() => ({}));\n        if (!res.ok) {\n          const detail = data.detail || data.message || JSON.stringify(data);\n          throw new Error(typeof detail === "string" ? detail : JSON.stringify(detail));\n        }\n        return data;\n      }\n\n      function renderFeed() {\n        const feed = $("economy-feed");\n        if (!state.results.length) {\n          feed.innerHTML = \'<div class="empty-feed">뉴스 검색을 실행하면 경제 기사 목록이 표시됩니다.</div>\';\n          return;\n        }\n        feed.innerHTML = state.results\n          .map((row, i) => {\n            const source = row.source || "뉴스";\n            const published = row.pubDate || "";\n            return `<article class="feed-post">\n              <div class="post-rail"><span class="post-rank-num">${i + 1}</span></div>\n              <div class="post-main">\n                <h3 class="post-title"><a href="${escAttr(row.link || "#")}" target="_blank" rel="noopener">${esc(row.title || "(제목 없음)")}</a></h3>\n                <div class="post-meta">\n                  <span>${esc(source)}</span>\n                  <span class="flair">${esc(published || "발행시각 없음")}</span>\n                </div>\n                <p class="post-excerpt">${esc(row.description || "")}</p>\n                <a class="post-footer-link" href="${escAttr(row.link || "#")}" target="_blank" rel="noopener">기사 원문 보기</a>\n              </div>\n            </article>`;\n          })\n          .join("");\n      }\n\n      function renderSignals() {\n        const el = $("economy-signals");\n        if (!state.results.length) {\n          el.textContent = "뉴스 검색 후 집계됩니다.";\n          el.className = "muted";\n          return;\n        }\n        const sourceCount = {};\n        state.results.forEach((row) => {\n          const source = row.source || "뉴스";\n          sourceCount[source] = (sourceCount[source] || 0) + 1;\n        });\n        const rows = Object.entries(sourceCount)\n          .sort((a, b) => b[1] - a[1])\n          .slice(0, 6);\n        el.className = "";\n        el.innerHTML = rows\n          .map(([name, count]) => `<div class="insight-item"><strong>${esc(name)}</strong><div class="muted">${count}건</div></div>`)\n          .join("");\n      }\n\n      function renderBriefing() {\n        $("economy-briefing").textContent = state.briefing || "(브리핑 없음)";\n      }\n\n      async function runSearch() {\n        const keyword = $("economy-keyword").value.trim();\n        const sort = $("economy-sort").value;\n        if (!keyword) {\n          setStatus("브리핑 키워드를 입력하세요.", true);\n          return;\n        }\n        setStatus("경제 뉴스 검색 중…");\n        try {\n          const data = await api("/economy/search", { keyword, sort });\n          state.results = data.results || [];\n          state.briefing = "";\n          renderFeed();\n          renderSignals();\n          renderBriefing();\n          setStatus(`완료 · ${state.results.length}건 · ${data.sort_label || ""}`);\n        } catch (error) {\n          setStatus(error.message, true);\n        }\n      }\n\n      async function runBriefing() {\n        const keyword = $("economy-keyword").value.trim();\n        const sort = $("economy-sort").value;\n        if (!keyword) {\n          setStatus("브리핑 키워드를 입력하세요.", true);\n          return;\n        }\n        setStatus("브리핑 생성 중…");\n        try {\n          const data = await api("/economy/briefing", { keyword, sort, results: state.results });\n          state.results = data.results || state.results;\n          state.briefing = data.briefing || "";\n          renderFeed();\n          renderSignals();\n          renderBriefing();\n          setStatus(`브리핑 완료 · ${data.count || state.results.length}건 기준`);\n        } catch (error) {\n          setStatus(error.message, true);\n        }\n      }\n\n      $("btn-economy-search").addEventListener("click", runSearch);\n      $("btn-economy-briefing").addEventListener("click", runBriefing);\n\n      renderFeed();\n      renderSignals();\n      renderBriefing();\n    </script>\n  </body>\n</html>\n'

WEATHER_BRIEFING_HTML = '<!DOCTYPE html>\n<html lang="ko">\n  <head>\n    <meta charset="utf-8" />\n    <meta name="viewport" content="width=device-width, initial-scale=1, viewport-fit=cover" />\n    <meta name="color-scheme" content="light dark" />\n    <meta name="theme-color" content="#1a1a1a" />\n    <title>날씨 데일리 브리핑 · 우아한빅토리 스튜디오</title>\n    <link rel="preconnect" href="https://fonts.googleapis.com" />\n    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin />\n    <link\n      href="https://fonts.googleapis.com/css2?family=IBM+Plex+Sans:wght@400;600;700&family=Plus+Jakarta+Sans:wght@700;800&display=swap"\n      rel="stylesheet"\n    />\n    <style>\n/* Reddit-style: high-contrast header, orange accent, dotted canvas, lifted cards */\n:root {\n  --canvas: #c9ccd1;\n  --canvas-dot: rgba(0, 0, 0, 0.07);\n  --card: #ffffff;\n  --border: #e1e4e8;\n  --border-strong: #b7bcc4;\n  --text: #0f0f0f;\n  --meta: #5c5f62;\n  --link: #006cbf;\n  --orange: #ff4500;\n  --orange-hot: #ff6a33;\n  --orange-hover: #e03d00;\n  --header-dark: #1a1a1b;\n  --header-border: #343536;\n  --shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.06);\n  --shadow-card: 0 4px 14px rgba(0, 0, 0, 0.12), 0 0 0 1px rgba(0, 0, 0, 0.04);\n  --shadow-card-hover: 0 8px 24px rgba(0, 0, 0, 0.14), 0 0 0 1px rgba(255, 69, 0, 0.12);\n  --radius: 6px;\n  --radius-card: 10px;\n  --tap-min: 46px;\n  --font: "IBM Plex Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial,\n    "Apple SD Gothic Neo", "Noto Sans KR", sans-serif;\n  --font-brand: "Plus Jakarta Sans", var(--font);\n}\n\n@media (prefers-color-scheme: dark) {\n  :root {\n    --canvas: #030303;\n    --canvas-dot: rgba(255, 255, 255, 0.04);\n    --card: #1a1a1b;\n    --border: #343536;\n    --border-strong: #56585a;\n    --text: #d7dadc;\n    --meta: #9fa1a3;\n    --link: #58a6ff;\n    --orange: #ff4500;\n    --orange-hot: #ff7849;\n    --orange-hover: #ff6a33;\n    --header-dark: #0b0b0c;\n    --header-border: #1f1f1f;\n    --shadow-sm: 0 1px 3px rgba(0, 0, 0, 0.5);\n    --shadow-card: 0 4px 18px rgba(0, 0, 0, 0.55), 0 0 0 1px #2a2a2b;\n    --shadow-card-hover: 0 10px 28px rgba(0, 0, 0, 0.65), 0 0 0 1px rgba(255, 69, 0, 0.35);\n  }\n}\n\n* {\n  box-sizing: border-box;\n}\n\nhtml {\n  -webkit-text-size-adjust: 100%;\n}\n\nbody {\n  margin: 0;\n  min-height: 100dvh;\n  font-family: var(--font);\n  font-size: 15px;\n  background-color: var(--canvas);\n  background-image: radial-gradient(circle at 1px 1px, var(--canvas-dot) 1px, transparent 0);\n  background-size: 18px 18px;\n  color: var(--text);\n  line-height: 1.55;\n  padding-bottom: env(safe-area-inset-bottom, 0);\n}\n\na {\n  color: var(--link);\n  text-decoration: none;\n}\na:hover {\n  text-decoration: underline;\n}\n\n/* —— Top bar (dark, Reddit-app feel) —— */\n.site-header {\n  position: sticky;\n  top: 0;\n  z-index: 200;\n  background: linear-gradient(180deg, #252526 0%, var(--header-dark) 100%);\n  border-bottom: 3px solid var(--orange);\n  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.25);\n  padding-top: env(safe-area-inset-top, 0);\n}\n\n@media (prefers-color-scheme: dark) {\n  .site-header {\n    background: linear-gradient(180deg, #121213 0%, var(--header-dark) 100%);\n  }\n}\n\n.header-inner {\n  max-width: 1248px;\n  margin: 0 auto;\n  padding: 0.75rem 1rem;\n  display: flex;\n  align-items: center;\n  min-height: 3.5rem;\n}\n\n.brand {\n  display: flex;\n  align-items: center;\n  gap: 0.85rem;\n  color: #fff;\n  text-decoration: none;\n}\n.brand:hover {\n  text-decoration: none;\n  filter: brightness(1.05);\n}\n\n.brand-mark {\n  width: 2.5rem;\n  height: 2.5rem;\n  border-radius: 50%;\n  background: radial-gradient(circle at 30% 25%, var(--orange-hot), var(--orange) 45%, #9b2300 100%);\n  flex-shrink: 0;\n  box-shadow: 0 0 0 3px rgba(255, 69, 0, 0.35), inset 0 2px 4px rgba(255, 255, 255, 0.35);\n}\n\n.brand-text {\n  display: flex;\n  flex-direction: column;\n  gap: 0.1rem;\n  line-height: 1.2;\n}\n\n.brand-name {\n  font-family: var(--font-brand);\n  font-weight: 800;\n  font-size: 1.28rem;\n  letter-spacing: -0.03em;\n  color: #fff;\n  text-shadow: 0 1px 2px rgba(0, 0, 0, 0.35);\n}\n\n.brand-sub {\n  font-size: 0.78rem;\n  color: #b7bdc2;\n  font-weight: 500;\n}\n\n/* —— Subreddit / sort strip —— */\n.community-strip {\n  background: linear-gradient(180deg, #e8eaed 0%, #dfe3e8 100%);\n  border-bottom: 1px solid var(--border-strong);\n  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.7);\n}\n\n@media (prefers-color-scheme: dark) {\n  .community-strip {\n    background: linear-gradient(180deg, #1f1f20 0%, #161617 100%);\n    border-bottom-color: var(--border);\n    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);\n  }\n}\n\n.community-strip-inner {\n  max-width: 1248px;\n  margin: 0 auto;\n  padding: 0.45rem 1rem;\n  display: flex;\n  align-items: center;\n  gap: 0.45rem;\n  flex-wrap: wrap;\n  row-gap: 0.35rem;\n  font-size: 0.8rem;\n  font-weight: 600;\n  color: var(--meta);\n}\n\n/* 우아한빅토리 · 스튜디오 — 한 덩어리로 붙여서 줄바꿈 시에도 떨어지지 않게 */\n.community-crumb {\n  display: inline-flex;\n  align-items: center;\n  flex-wrap: nowrap;\n  gap: 0.28rem;\n  white-space: nowrap;\n}\n\n.community-crumb .crumb-sep {\n  margin: 0;\n  flex-shrink: 0;\n}\n\n.sort-pill {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  min-height: 28px;\n  padding: 0 0.65rem;\n  border-radius: 999px;\n  background: var(--card);\n  border: 1px solid var(--border-strong);\n  color: var(--meta);\n  box-shadow: var(--shadow-sm);\n}\n\n.sort-pill.is-on {\n  background: var(--orange);\n  border-color: var(--orange);\n  color: #fff;\n  box-shadow: 0 2px 8px rgba(255, 69, 0, 0.45);\n}\n\n.community-dot {\n  color: var(--border-strong);\n  font-weight: 400;\n  margin: 0 0.1rem;\n  user-select: none;\n}\n\n.community-name-ko {\n  color: var(--orange);\n  font-weight: 800;\n  font-family: var(--font);\n}\n\n.community-tagline {\n  color: var(--meta);\n  font-weight: 600;\n  word-break: keep-all;\n}\n\n@media (prefers-color-scheme: dark) {\n  .sort-pill {\n    background: #2a2a2b;\n    border-color: #3d3d3e;\n    color: #b7bdc2;\n  }\n}\n\n/* —— Body shell: 항상 「좌측 메뉴 열 + 본문」 (좁은 화면은 메뉴 열 폭만 줄임) —— */\n.body-shell {\n  max-width: 1248px;\n  margin: 0 auto;\n  padding: 0.85rem 0.85rem 2.25rem;\n  display: grid;\n  grid-template-columns: minmax(200px, 220px) minmax(0, 1fr);\n  gap: 1rem;\n  align-items: start;\n}\n\n/* 태블릿·모바일도 2열 유지: 메뉴는 왼쪽 세로 리스트 */\n@media (max-width: 960px) {\n  .body-shell {\n    grid-template-columns: minmax(132px, 34vw) minmax(0, 1fr);\n    gap: 0.65rem;\n    padding: 0.55rem 0.45rem 1.75rem;\n  }\n}\n\n/* 극소 화면: 메뉴를 위에 전체 너비 세로로 두고, 본문은 아래(여전히 왼쪽 정렬 리스트) */\n@media (max-width: 380px) {\n  .body-shell {\n    grid-template-columns: 1fr;\n    padding: 0.4rem 0.4rem 1.5rem;\n  }\n}\n\n.layout-main {\n  min-width: 0;\n}\n\n.left-nav {\n  background: var(--card);\n  border: 1px solid var(--border);\n  border-radius: var(--radius-card);\n  padding: 0.5rem 0;\n  box-shadow: var(--shadow-card);\n  position: sticky;\n  top: 4.85rem;\n  z-index: 40;\n  align-self: start;\n  border-right: 3px solid rgba(255, 69, 0, 0.2);\n}\n\n@media (max-width: 380px) {\n  .left-nav {\n    position: static;\n    top: auto;\n    margin-bottom: 0.65rem;\n    border-right: 1px solid var(--border);\n    border-bottom: 3px solid rgba(255, 69, 0, 0.25);\n  }\n}\n\n.left-nav-heading {\n  margin: 0 0 0.25rem;\n  padding: 0 0.85rem 0.45rem;\n  font-size: 0.65rem;\n  font-weight: 800;\n  text-transform: uppercase;\n  letter-spacing: 0.1em;\n  color: var(--meta);\n  border-bottom: 1px solid var(--border);\n}\n\n@media (max-width: 960px) {\n  .left-nav-heading {\n    padding-left: 0.55rem;\n    padding-right: 0.45rem;\n    font-size: 0.6rem;\n  }\n}\n\n.nav-item {\n  display: flex;\n  align-items: flex-start;\n  gap: 0.45rem;\n  padding: 0.58rem 0.75rem;\n  color: var(--text);\n  font-weight: 600;\n  font-size: 0.9rem;\n  text-decoration: none;\n  border-left: 3px solid transparent;\n  transition: background 0.12s ease, border-color 0.12s ease;\n}\n\n.nav-item:hover {\n  background: var(--canvas);\n  text-decoration: none;\n}\n\n.nav-item.is-active {\n  border-left-color: var(--orange);\n  background: rgba(255, 69, 0, 0.1);\n  font-weight: 800;\n}\n\n@media (prefers-color-scheme: dark) {\n  .nav-item.is-active {\n    background: rgba(255, 69, 0, 0.14);\n  }\n}\n\n@media (max-width: 960px) {\n  .nav-item {\n    padding: 0.5rem 0.5rem;\n    font-size: 0.78rem;\n    gap: 0.35rem;\n  }\n}\n\n@media (max-width: 380px) {\n  .nav-item {\n    font-size: 0.85rem;\n    padding: 0.55rem 0.85rem;\n  }\n}\n\n.nav-icon {\n  width: 1.25rem;\n  text-align: center;\n  font-size: 1.05rem;\n  line-height: 1;\n  opacity: 0.9;\n}\n\n.nav-label {\n  line-height: 1.3;\n  word-break: keep-all;\n  overflow-wrap: break-word;\n}\n\n/* —— Main two-column (feed + right sidebar) —— */\n.page-wrap {\n  margin: 0;\n  padding: 0;\n  display: grid;\n  grid-template-columns: minmax(0, 1fr) 280px;\n  gap: 1.15rem;\n  align-items: start;\n}\n\n@media (max-width: 960px) {\n  .page-wrap {\n    grid-template-columns: 1fr;\n  }\n}\n\n/* —— Standalone placeholder page (브리핑 등) —— */\n.placeholder-page {\n  min-width: 0;\n}\n\n.placeholder-hero {\n  background: var(--card);\n  border: 1px solid var(--border);\n  border-radius: var(--radius-card);\n  padding: 1.35rem 1.25rem 1.5rem;\n  box-shadow: var(--shadow-card);\n  border-top: 4px solid var(--orange);\n}\n\n.placeholder-hero h1 {\n  margin: 0 0 0.5rem;\n  font-family: var(--font-brand);\n  font-size: 1.35rem;\n  font-weight: 800;\n  letter-spacing: -0.02em;\n}\n\n.placeholder-hero .lede {\n  margin: 0;\n  font-size: 0.95rem;\n  color: var(--meta);\n  line-height: 1.55;\n}\n\n.placeholder-badge {\n  display: inline-block;\n  margin-bottom: 0.65rem;\n  padding: 0.2rem 0.55rem;\n  border-radius: 999px;\n  font-size: 0.65rem;\n  font-weight: 800;\n  text-transform: uppercase;\n  letter-spacing: 0.06em;\n  background: rgba(255, 69, 0, 0.12);\n  border: 1px solid rgba(255, 69, 0, 0.35);\n  color: var(--orange);\n}\n\n.feed-column {\n  min-width: 0;\n}\n\n.sidebar {\n  min-width: 0;\n}\n\n@media (max-width: 960px) {\n  .sidebar {\n    order: 3;\n  }\n}\n\n/* —— Section titles —— */\n.section-title {\n  margin: 1.15rem 0 0.55rem;\n  padding-left: 0.65rem;\n  border-left: 4px solid var(--orange);\n  font-size: 0.7rem;\n  font-weight: 800;\n  text-transform: uppercase;\n  letter-spacing: 0.12em;\n  color: var(--meta);\n  line-height: 1.2;\n}\n\n.section-title:first-of-type {\n  margin-top: 0;\n}\n\n/* —— Composer (create post) —— */\n.create-card {\n  position: relative;\n  background: var(--card);\n  border: 1px solid var(--border);\n  border-radius: var(--radius-card);\n  padding: 1rem 1.1rem 1.1rem;\n  margin-bottom: 0.85rem;\n  box-shadow: var(--shadow-card);\n  border-top: 4px solid var(--orange);\n}\n\n.create-card::before {\n  content: "글쓰기";\n  position: absolute;\n  top: 0.65rem;\n  right: 1rem;\n  font-size: 0.65rem;\n  font-weight: 800;\n  text-transform: uppercase;\n  letter-spacing: 0.08em;\n  color: var(--orange);\n  opacity: 0.85;\n}\n\n.create-card label {\n  display: block;\n  font-size: 0.7rem;\n  font-weight: 800;\n  text-transform: uppercase;\n  letter-spacing: 0.06em;\n  color: var(--meta);\n  margin-bottom: 0.4rem;\n}\n\n.field-row {\n  display: grid;\n  grid-template-columns: 1fr 1fr;\n  gap: 0.85rem;\n  margin-top: 0.85rem;\n}\n\n@media (max-width: 560px) {\n  .field-row {\n    grid-template-columns: 1fr;\n  }\n}\n\ninput[type="text"],\nselect,\ntextarea {\n  width: 100%;\n  padding: 0.7rem 0.85rem;\n  border: 2px solid var(--border-strong);\n  border-radius: var(--radius);\n  font: inherit;\n  font-size: 16px;\n  background: var(--card);\n  color: var(--text);\n  transition: border-color 0.15s ease, box-shadow 0.15s ease;\n}\n\ninput[type="text"]:focus,\nselect:focus,\ntextarea:focus {\n  outline: none;\n  border-color: var(--orange);\n  box-shadow: 0 0 0 3px rgba(255, 69, 0, 0.2);\n}\n\n/* —— Actions —— */\n.action-bar {\n  display: flex;\n  flex-wrap: nowrap;\n  gap: 0.55rem;\n  margin-top: 1rem;\n  padding: 0.15rem 0 0.2rem;\n  overflow-x: auto;\n  -webkit-overflow-scrolling: touch;\n  scrollbar-width: thin;\n}\n\n.action-bar::-webkit-scrollbar {\n  height: 5px;\n}\n\n.action-bar::-webkit-scrollbar-thumb {\n  background: var(--border-strong);\n  border-radius: 4px;\n}\n\n.action-bar button {\n  flex: 0 0 auto;\n  min-height: var(--tap-min);\n  padding: 0 1.1rem;\n  border-radius: 999px;\n  font: inherit;\n  font-size: 0.9rem;\n  font-weight: 800;\n  cursor: pointer;\n  border: 2px solid transparent;\n  white-space: nowrap;\n  transition: transform 0.12s ease, box-shadow 0.12s ease;\n}\n\n.action-bar button:active {\n  transform: scale(0.97);\n}\n\n.btn-secondary {\n  background: var(--card);\n  border-color: var(--border-strong);\n  color: var(--text);\n  box-shadow: var(--shadow-sm);\n}\n\n.btn-secondary:hover {\n  background: var(--canvas);\n  border-color: var(--meta);\n}\n\n.btn-primary {\n  background: linear-gradient(180deg, var(--orange-hot) 0%, var(--orange) 100%);\n  color: #fff;\n  border-color: #c73a00;\n  box-shadow: 0 3px 12px rgba(255, 69, 0, 0.45), inset 0 1px 0 rgba(255, 255, 255, 0.25);\n}\n\n.btn-primary:hover {\n  background: linear-gradient(180deg, #ff7a45 0%, var(--orange-hot) 100%);\n  box-shadow: 0 5px 18px rgba(255, 69, 0, 0.5);\n}\n\nbutton:disabled {\n  opacity: 0.5;\n  cursor: not-allowed;\n}\n\n#status {\n  margin-top: 0.75rem;\n  font-size: 0.9rem;\n  min-height: 1.3rem;\n  font-weight: 600;\n}\n\n.err {\n  color: var(--orange);\n}\n\n.ok {\n  color: #0a8f2d;\n}\n\n@media (prefers-color-scheme: dark) {\n  .ok {\n    color: #55bd46;\n  }\n}\n\n.muted {\n  color: var(--meta);\n  font-size: 0.9rem;\n}\n\n/* —— Feed —— */\n.feed-list {\n  display: flex;\n  flex-direction: column;\n  gap: 0.75rem;\n}\n\n.feed-post {\n  display: flex;\n  background: var(--card);\n  border: 1px solid var(--border);\n  border-radius: var(--radius-card);\n  overflow: hidden;\n  box-shadow: var(--shadow-card);\n  transition: box-shadow 0.2s ease, transform 0.2s ease;\n}\n\n.feed-post:hover {\n  box-shadow: var(--shadow-card-hover);\n  transform: translateY(-2px);\n}\n\n.post-rail {\n  width: 2.85rem;\n  flex-shrink: 0;\n  background: linear-gradient(180deg, rgba(255, 69, 0, 0.12) 0%, var(--canvas) 55%);\n  border-right: 1px solid var(--border);\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  padding: 0.65rem 0.3rem;\n}\n\n.post-rank-num {\n  font-size: 0.75rem;\n  font-weight: 900;\n  color: var(--orange);\n  line-height: 1;\n}\n\n.post-main {\n  flex: 1;\n  min-width: 0;\n  padding: 0.75rem 1rem 0.9rem;\n}\n\n.post-title {\n  margin: 0 0 0.4rem;\n  font-size: 1.08rem;\n  font-weight: 700;\n  line-height: 1.35;\n}\n\n.post-title a {\n  color: var(--text);\n}\n.post-title a:hover {\n  color: var(--link);\n  text-decoration: none;\n}\n\n.post-meta {\n  font-size: 0.78rem;\n  color: var(--meta);\n  margin-bottom: 0.55rem;\n  display: flex;\n  flex-wrap: wrap;\n  gap: 0.4rem;\n  align-items: center;\n}\n\n.flair {\n  display: inline-block;\n  padding: 0.15rem 0.5rem;\n  border-radius: 999px;\n  background: rgba(255, 69, 0, 0.1);\n  border: 1px solid rgba(255, 69, 0, 0.35);\n  font-size: 0.62rem;\n  font-weight: 800;\n  text-transform: uppercase;\n  letter-spacing: 0.04em;\n  color: var(--orange);\n}\n\n@media (prefers-color-scheme: dark) {\n  .flair {\n    background: rgba(255, 69, 0, 0.15);\n  }\n}\n\n.post-excerpt {\n  margin: 0;\n  font-size: 0.9rem;\n  color: var(--text);\n  line-height: 1.5;\n  display: -webkit-box;\n  -webkit-line-clamp: 4;\n  -webkit-box-orient: vertical;\n  overflow: hidden;\n}\n\n.post-footer-link {\n  display: inline-block;\n  margin-top: 0.55rem;\n  font-size: 0.82rem;\n  font-weight: 800;\n}\n\n.empty-feed {\n  background: var(--card);\n  border: 2px dashed var(--border-strong);\n  border-radius: var(--radius-card);\n  padding: 2.25rem 1.25rem;\n  text-align: center;\n  color: var(--meta);\n  font-size: 0.95rem;\n  font-weight: 600;\n  box-shadow: var(--shadow-sm);\n}\n\n/* —— Sidebar —— */\n.widget {\n  background: var(--card);\n  border: 1px solid var(--border);\n  border-radius: var(--radius-card);\n  padding: 0.95rem;\n  margin-bottom: 0.85rem;\n  box-shadow: var(--shadow-card);\n}\n\n.widget .section-title {\n  margin: 0 0 0.75rem;\n  padding-left: 0.55rem;\n  border-left-width: 3px;\n}\n\n.insight-item {\n  padding: 0.55rem 0;\n  border-bottom: 1px solid var(--border);\n  font-size: 0.88rem;\n}\n.insight-item:last-child {\n  border-bottom: none;\n}\n\n.insight-item strong {\n  display: block;\n  margin-bottom: 0.25rem;\n  line-height: 1.35;\n}\n\n.analysis-block {\n  margin-bottom: 1.1rem;\n  padding-bottom: 1.1rem;\n  border-bottom: 1px solid var(--border);\n}\n.analysis-block:last-child {\n  margin-bottom: 0;\n  padding-bottom: 0;\n  border-bottom: none;\n}\n\npre.out {\n  white-space: pre-wrap;\n  word-break: break-word;\n  font-size: 0.82rem;\n  line-height: 1.55;\n  max-height: min(52vh, 440px);\n  overflow: auto;\n  background: var(--canvas);\n  padding: 1rem;\n  border-radius: var(--radius);\n  border: 1px solid var(--border);\n  margin: 0;\n  font-family: ui-monospace, "Cascadia Code", "Source Code Pro", Menlo, Consolas, monospace;\n}\n\n#summary {\n  font-size: 0.9rem;\n  line-height: 1.6;\n}\n\n    </style>\n  </head>\n  <body>\n    <header class="site-header">\n      <div class="header-inner">\n        <a href="/" class="brand">\n          <span class="brand-mark" aria-hidden="true"></span>\n          <span class="brand-text">\n            <span class="brand-name">우아한빅토리 스튜디오</span>\n            <span class="brand-sub">검색 · 분석 · 초안 · 한 화면에서</span>\n          </span>\n        </a>\n      </div>\n    </header>\n\n    <div class="community-strip" aria-hidden="true">\n      <div class="community-strip-inner">\n        <span class="sort-pill is-on">BEST</span>\n        <span class="sort-pill">HOT</span>\n        <span class="sort-pill">NEW</span>\n        <span class="community-dot" aria-hidden="true">·</span>\n        <span class="community-crumb" translate="no">\n          <strong class="community-name-ko">우아한빅토리</strong>\n          <span class="community-dot crumb-sep" aria-hidden="true">·</span>\n          <span class="community-tagline">스튜디오</span>\n        </span>\n      </div>\n    </div>\n\n    <div class="body-shell">\n      <nav class="left-nav" aria-label="주요 메뉴">\n        <p class="left-nav-heading">탐색</p>\n        <a href="/" class="nav-item">\n          <span class="nav-icon" aria-hidden="true">⌂</span>\n          <span class="nav-label">인기 블로그 분석 및 요약</span>\n        </a>\n        <a href="/economy-briefing" class="nav-item">\n          <span class="nav-icon" aria-hidden="true">▤</span>\n          <span class="nav-label">경제 데일리 브리핑</span>\n        </a>\n        <a href="/weather-briefing" class="nav-item is-active">\n          <span class="nav-icon" aria-hidden="true">☁</span>\n          <span class="nav-label">날씨 데일리 브리핑</span>\n        </a>\n      </nav>\n\n      <div class="layout-main">\n        <div class="page-wrap">\n          <div class="feed-column">\n            <div class="create-card">\n              <label for="weather-regions">지역 목록 (쉼표 구분)</label>\n              <input\n                id="weather-regions"\n                type="text"\n                value="서울, 부산, 대구, 광주, 제주"\n                placeholder="예: 서울, 인천, 수원, 대전"\n                autocomplete="off"\n              />\n\n              <div class="action-bar">\n                <button type="button" class="btn-primary" id="btn-weather-search">지역별 실시간 검색</button>\n                <button type="button" class="btn-secondary" id="btn-weather-briefing">브리핑 생성</button>\n              </div>\n              <div id="weather-status" class="muted"></div>\n            </div>\n\n            <h2 class="section-title">지역별 실시간 날씨</h2>\n            <div id="weather-feed" class="feed-list"></div>\n\n            <h2 class="section-title">오늘의 날씨 브리핑</h2>\n            <div class="widget">\n              <pre class="out" id="weather-briefing">(브리핑 없음)</pre>\n            </div>\n          </div>\n\n          <aside class="sidebar">\n            <div class="widget">\n              <h2 class="section-title">체감 설명 기준</h2>\n              <div class="muted">\n                <strong>바람 강도(m/s)</strong><br />\n                0~2: 거의 무풍 · 2~5: 산들바람 · 5~9: 우산 흔들림 · 9~14: 보행 저항 · 14+: 강풍<br /><br />\n                <strong>강수량(mm/h)</strong><br />\n                0: 비 없음 · 0~1: 이슬비 · 1~5: 약한 비 · 5~15: 중간 비 · 15+: 강한 비\n              </div>\n            </div>\n            <div class="widget">\n              <h2 class="section-title">시간대 예보</h2>\n              <div id="weather-timeline" class="muted">실시간 검색 후 지역별 8시간 예보가 표시됩니다.</div>\n            </div>\n          </aside>\n        </div>\n      </div>\n    </div>\n\n    <script type="module">\n      const $ = (id) => document.getElementById(id);\n      const state = { items: [], briefing: "" };\n\n      function esc(value) {\n        return String(value)\n          .replace(/&/g, "&amp;")\n          .replace(/</g, "&lt;")\n          .replace(/>/g, "&gt;")\n          .replace(/"/g, "&quot;");\n      }\n\n      function setStatus(message, isErr = false) {\n        const el = $("weather-status");\n        el.textContent = message;\n        el.className = isErr ? "err" : "ok";\n      }\n\n      function parseRegions() {\n        return $("weather-regions")\n          .value.split(",")\n          .map((s) => s.trim())\n          .filter(Boolean);\n      }\n\n      async function api(path, body) {\n        const res = await fetch(`/api${path}`, {\n          method: "POST",\n          headers: { "Content-Type": "application/json" },\n          body: JSON.stringify(body),\n        });\n        const data = await res.json().catch(() => ({}));\n        if (!res.ok) {\n          const detail = data.detail || data.message || JSON.stringify(data);\n          throw new Error(typeof detail === "string" ? detail : JSON.stringify(detail));\n        }\n        return data;\n      }\n\n      function renderFeed() {\n        const feed = $("weather-feed");\n        if (!state.items.length) {\n          feed.innerHTML = \'<div class="empty-feed">지역별 실시간 검색을 실행하면 날씨 카드가 표시됩니다.</div>\';\n          return;\n        }\n        feed.innerHTML = state.items\n          .map((row, idx) => {\n            if (!row.ok) {\n              return `<article class="feed-post">\n                <div class="post-rail"><span class="post-rank-num">${idx + 1}</span></div>\n                <div class="post-main">\n                  <h3 class="post-title">${esc(row.region_query || "지역")}</h3>\n                  <p class="post-excerpt">조회 실패: ${esc(row.error || "알 수 없는 오류")}</p>\n                </div>\n              </article>`;\n            }\n            const loc = row.location || {};\n            const cur = (row.weather || {}).current || {};\n            return `<article class="feed-post">\n              <div class="post-rail"><span class="post-rank-num">${idx + 1}</span></div>\n              <div class="post-main">\n                <h3 class="post-title">${esc(loc.name || row.region_query)} ${esc(cur.icon || "🌤️")} ${esc(cur.condition || "")}</h3>\n                <div class="post-meta">\n                  <span>${esc(loc.admin || loc.country || "")}</span>\n                  <span class="flair">${esc((cur.temperature_c ?? "-") + "°C / 체감 " + (cur.feels_like_c ?? "-") + "°C")}</span>\n                </div>\n                <p class="post-excerpt">\n                  바람 ${esc(String(cur.wind_mps ?? "-"))} m/s · ${esc(cur.wind_feel || "")}<br />\n                  강수 ${esc(String(cur.precipitation_mm ?? "-"))} mm/h · ${esc(cur.rain_feel || "")}\n                </p>\n              </div>\n            </article>`;\n          })\n          .join("");\n      }\n\n      function renderTimeline() {\n        const el = $("weather-timeline");\n        const okItems = state.items.filter((x) => x.ok);\n        if (!okItems.length) {\n          el.textContent = "실시간 검색 후 지역별 8시간 예보가 표시됩니다.";\n          el.className = "muted";\n          return;\n        }\n        el.className = "";\n        el.innerHTML = okItems\n          .slice(0, 3)\n          .map((row) => {\n            const name = row.location?.name || row.region_query || "지역";\n            const lines = (row.weather?.timeline || [])\n              .slice(0, 8)\n              .map(\n                (t) =>\n                  `<div class="insight-item"><strong>${esc(t.time)} ${esc(t.icon || "🌤️")} ${esc(t.condition || "")}</strong><div class="muted">${esc(\n                    `${t.temperature_c ?? "-"}°C · 바람 ${t.wind_mps ?? "-"} m/s · 강수확률 ${t.precip_probability ?? "-"}%`\n                  )}</div></div>`\n              )\n              .join("");\n            return `<div style="margin-bottom:0.8rem"><strong>${esc(name)}</strong>${lines}</div>`;\n          })\n          .join("");\n      }\n\n      function renderBriefing() {\n        $("weather-briefing").textContent = state.briefing || "(브리핑 없음)";\n      }\n\n      async function runSearch() {\n        const regions = parseRegions();\n        if (!regions.length) {\n          setStatus("지역을 1개 이상 입력하세요.", true);\n          return;\n        }\n        setStatus("지역별 실시간 날씨 조회 중…");\n        try {\n          const data = await api("/weather/search", { regions });\n          state.items = data.items || [];\n          state.briefing = "";\n          renderFeed();\n          renderTimeline();\n          renderBriefing();\n          setStatus(`완료 · ${state.items.length}개 지역`);\n        } catch (error) {\n          setStatus(error.message, true);\n        }\n      }\n\n      async function runBriefing() {\n        const regions = parseRegions();\n        if (!regions.length) {\n          setStatus("지역을 1개 이상 입력하세요.", true);\n          return;\n        }\n        setStatus("날씨 브리핑 생성 중…");\n        try {\n          const data = await api("/weather/briefing", { regions });\n          state.items = data.items || [];\n          state.briefing = data.briefing || "";\n          renderFeed();\n          renderTimeline();\n          renderBriefing();\n          setStatus("날씨 브리핑 생성 완료");\n        } catch (error) {\n          setStatus(error.message, true);\n        }\n      }\n\n      $("btn-weather-search").addEventListener("click", runSearch);\n      $("btn-weather-briefing").addEventListener("click", runBriefing);\n\n      renderFeed();\n      renderTimeline();\n      renderBriefing();\n    </script>\n  </body>\n</html>\n'

