class SearchBody(BaseModel):
    keyword: str = Field(..., min_length=1)
    sort: Literal["sim", "date"] = "sim"


class AnalyzeBody(BaseModel):
    results: list[dict[str, Any]]


class GenerateBody(BaseModel):
    keyword: str
    tone: str = "전문가톤"
    analyzed: list[dict[str, Any]]


class SummarizeBody(BaseModel):
    keyword: str
    analyzed: list[dict[str, Any]]


class ImagesBody(BaseModel):
    keyword: str
    markdown: str


class EconomySearchBody(BaseModel):
    keyword: str = Field(..., min_length=1)
    sort: Literal["sim", "date"] = "date"


class EconomyBriefingBody(BaseModel):
    keyword: str = Field(..., min_length=1)
    sort: Literal["sim", "date"] = "date"
    results: list[dict[str, Any]] = Field(default_factory=list)


class WeatherRegionsBody(BaseModel):
    regions: list[str] = Field(default_factory=list, min_length=1)


@router.get("/health")
def health() -> dict[str, bool]:
    return {"ok": True}


@router.post("/search")
async def search(body: SearchBody) -> dict[str, Any]:
    try:
        rows = await svc.search_blog_by_naver_mcp(body.keyword.strip(), display=10, sort=body.sort)
        label = "관련도(sim)" if body.sort == "sim" else "최신순(date)"
        rows = [{**item, "ranking_basis": label} for item in rows]
        return {"results": rows, "sort": body.sort, "sort_label": label}
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    except Exception as exc:
        raise HTTPException(status_code=500, detail=str(exc)) from exc


@router.post("/analyze")
def analyze(body: AnalyzeBody) -> dict[str, Any]:
    if not body.results:
        raise HTTPException(status_code=400, detail="results 비어 있음")
    analyzed = svc.analyze_top_results(body.results, top_n=5)
    return {"analyzed": analyzed}


@router.post("/generate")
def generate(body: GenerateBody) -> dict[str, Any]:
    refs = [r for r in body.analyzed if r.get("analysis_ok")][:5]
    if len(refs) < 3:
        raise HTTPException(status_code=400, detail="분석 가능한 참조가 부족합니다(최소 3개).")
    md = svc.llm_generate_article(body.keyword, refs, body.tone)
    return {"markdown": md}


@router.post("/summarize")
def summarize(body: SummarizeBody) -> dict[str, Any]:
    if not body.analyzed:
        raise HTTPException(status_code=400, detail="analyzed 비어 있음")
    text = svc.build_clear_thought_summary(body.keyword, body.analyzed)
    return {"summary": text}


@router.post("/images")
def images(body: ImagesBody) -> dict[str, Any]:
    token = svc.get_replicate_token()
    out = svc.generate_images_auto(body.keyword or "블로그", body.markdown, token)
    if not out["ok"]:
        raise HTTPException(status_code=500, detail=out["error"])
    items_out = []
    for item in out["items"]:
        items_out.append(
            {
                "filename": item["filename"],
                "content_base64": base64.b64encode(item["content"]).decode("ascii"),
            }
        )
    md = svc.inject_images_into_markdown_items(body.markdown, out["items"])
    return {
        "markdown": md,
        "images": items_out,
        "replicate_configured": bool(token),
    }


@router.post("/economy/search")
async def economy_search(body: EconomySearchBody) -> dict[str, Any]:
    try:
        rows = await svc.search_news_by_naver_api(body.keyword.strip(), display=12, sort=body.sort)
        label = "최신순(date)" if body.sort == "date" else "관련도(sim)"
        return {"results": rows, "sort": body.sort, "sort_label": label}
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    except Exception as exc:
        raise HTTPException(status_code=500, detail=str(exc)) from exc


@router.post("/economy/briefing")
async def economy_briefing(body: EconomyBriefingBody) -> dict[str, Any]:
    try:
        keyword = body.keyword.strip()
        rows = body.results
        if not rows:
            rows = await svc.search_news_by_naver_api(keyword, display=12, sort=body.sort)
        briefing = svc.build_economy_briefing(keyword, rows)
        return {"briefing": briefing, "results": rows, "count": len(rows)}
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    except Exception as exc:
        raise HTTPException(status_code=500, detail=str(exc)) from exc


@router.post("/weather/search")
async def weather_search(body: WeatherRegionsBody) -> dict[str, Any]:
    try:
        out = await svc.build_weather_briefing_for_regions(body.regions)
        return {"items": out["items"], "count": len(out["items"])}
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    except Exception as exc:
        raise HTTPException(status_code=500, detail=str(exc)) from exc


@router.post("/weather/briefing")
async def weather_briefing(body: WeatherRegionsBody) -> dict[str, Any]:
    try:
        out = await svc.build_weather_briefing_for_regions(body.regions)
        return {"items": out["items"], "briefing": out["briefing"]}
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    except Exception as exc:
        raise HTTPException(status_code=500, detail=str(exc)) from exc


app.include_router(router)

